func TestCloneStaticActorSnapshotsClonesRewardDropVnums(t *testing.T) {
	original := []StaticActorSnapshot{{
		EntityID:         0x07000101,
		Name:             "RewardCloneMob",
		MapIndex:         bootstrapMapIndex,
		X:                1200,
		Y:                2200,
		RaceNum:          20350,
		CombatProfile:    string(worldruntime.StaticActorCombatProfileTrainingDummy),
		SpawnGroupRef:    "practice.reward_clone",
		RewardExperience: 75,
		RewardGold:       60,
		RewardDropVnums:  []uint32{27001, 27002},
	}}

	cloned := cloneStaticActorSnapshots(original)
	if len(cloned) != 1 {
		t.Fatalf("expected one cloned static actor, got %d", len(cloned))
	}
	cloned[0].RewardDropVnums[0] = 99999
	if original[0].RewardDropVnums[0] != 27001 {
		t.Fatalf("expected reward drop vnums to be deep-cloned, original mutated to %+v", original[0].RewardDropVnums)
	}
}

func TestLegacyCreatePositionForEmpireCoversOwnedTownRestartTable(t *testing.T) {
	tests := []struct {
		name         string
		empire       uint8
		wantMapIndex uint32
		wantX        int32
		wantY        int32
	}{
		{name: "empire one", empire: 1, wantMapIndex: bootstrapMapIndex, wantX: 459800, wantY: 953900},
		{name: "empire two", empire: 2, wantMapIndex: 21, wantX: 52070, wantY: 166600},
		{name: "empire three", empire: 3, wantMapIndex: 41, wantX: 957300, wantY: 255200},
		{name: "unknown falls back to empire one", empire: 0, wantMapIndex: bootstrapMapIndex, wantX: 459800, wantY: 953900},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			gotMapIndex, gotX, gotY := legacyCreatePositionForEmpire(tt.empire)
			if gotMapIndex != tt.wantMapIndex || gotX != tt.wantX || gotY != tt.wantY {
				t.Fatalf("legacyCreatePositionForEmpire(%d) = map=%d x=%d y=%d, want map=%d x=%d y=%d", tt.empire, gotMapIndex, gotX, gotY, tt.wantMapIndex, tt.wantX, tt.wantY)
			}
		})
	}
}

func TestStaticActorCharacterAdditionalInfoUsesCombatProfileLevel(t *testing.T) {
	actor := worldruntime.StaticEntity{
		Entity: worldruntime.Entity{
			ID:   0x07000001,
			Kind: worldruntime.EntityKindStaticActor,
			VID:  0x07000001,
			Name: "Practice Mob Level Probe",
		},
		Position:      worldruntime.NewPosition(bootstrapMapIndex, 1200, 2200),
		RaceNum:       20350,
		CombatProfile: worldruntime.StaticActorCombatProfilePracticeMob,
		SpawnGroupRef: "practice.mob_level_probe",
	}

	packet := staticActorCharacterAdditionalInfoPacket(actor, uint32(actor.Entity.ID))
	if packet.Level != uint32(worldruntime.PracticeMobBootstrapLevel) {
		t.Fatalf("expected static actor additional info level %d from combat profile, got %d", worldruntime.PracticeMobBootstrapLevel, packet.Level)
	}
}

type loadableFailingAccountStore struct {
	account accountstore.Account
	saveErr error
}

func (s loadableFailingAccountStore) Load(login string) (accountstore.Account, error) {
	if s.account.Login != login {
		return accountstore.Account{}, accountstore.ErrAccountNotFound
	}
	return accountstore.Account{
		Login:      s.account.Login,
		Empire:     s.account.Empire,
		Characters: cloneCharacters(s.account.Characters),
	}, nil
}

func (s loadableFailingAccountStore) Save(accountstore.Account) error {
	if s.saveErr != nil {
		return s.saveErr
	}
	return errors.New("account save failed")
}

func TestNewGameSessionFactoryTransferRebootstrapAppendsDestinationStaticActorFrames(t *testing.T) {
	store := loginticket.NewFileStore(t.TempDir())
	accounts := accountstore.NewFileStore(t.TempDir())
	mover := peerVisibilityCharacter("StaticTransferMover", 0x01030170, 0x02040170, 1100, 2100, 0, 101, 201)
	mover.MapIndex = bootstrapMapIndex
	mover.X = 1100
	mover.Y = 2100
	issuePeerTicket(t, store, "static-transfer-mover", 0x17171717, mover)
	if err := accounts.Save(accountstore.Account{Login: "static-transfer-mover", Empire: mover.Empire, Characters: []loginticket.Character{mover}}); err != nil {
		t.Fatalf("save mover account: %v", err)
	}

	staticActorStore := staticstore.NewFileStore(t.TempDir() + "/static-actors.json")
	interactionStore := interactionstore.NewFileStore(t.TempDir() + "/interaction-definitions.json")
	runtime, err := newGameRuntimeWithStoresAndTransferTriggers(
		config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"},
		store,
		accounts,
		staticActorStore,
		interactionStore,
		[]bootstrapTransferTrigger{{
			SourceMapIndex: bootstrapMapIndex,
			SourceX:        1200,
			SourceY:        2200,
			TargetMapIndex: 42,
			TargetX:        5100,
			TargetY:        6100,
		}},
	)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	actor, ok := runtime.RegisterStaticActor("Destination Gate Guard", 42, 5125, 6125, 101)
	if !ok {
		t.Fatal("expected destination static actor registration to succeed")
	}

	flow, enterOut := enterGameWithLoginTicket(t, runtime.SessionFactory(), "static-transfer-mover", 0x17171717)
	defer closeSessionFlow(t, flow)
	if len(enterOut) != 5 {
		t.Fatalf("expected no source static actor in initial bootstrap, got %d frames", len(enterOut))
	}

	moveOut, err := flow.HandleClientFrame(decodeSingleFrame(t, movep.EncodeMove(movep.MovePacket{Func: 1, X: 1200, Y: 2200, Time: 99})))
	if err != nil {
		t.Fatalf("unexpected transfer-triggering move error: %v", err)
	}
	if len(moveOut) != 7 {
		t.Fatalf("expected 4 self bootstrap frames plus 3 destination static-actor frames, got %d", len(moveOut))
	}
	selfAdd, err := worldproto.DecodeCharacterAdd(decodeSingleFrame(t, moveOut[0]))
	if err != nil {
		t.Fatalf("decode transfer self character add: %v", err)
	}
	if selfAdd.VID != mover.VID || selfAdd.X != 5100 || selfAdd.Y != 6100 {
		t.Fatalf("unexpected transfer self character add: %+v", selfAdd)
	}
	destinationActorAdd, err := worldproto.DecodeCharacterAdd(decodeSingleFrame(t, moveOut[4]))
	if err != nil {
		t.Fatalf("decode destination static actor add after transfer: %v", err)
	}
	if destinationActorAdd.VID != uint32(actor.EntityID) || destinationActorAdd.X != actor.X || destinationActorAdd.Y != actor.Y || destinationActorAdd.Type != 1 {
		t.Fatalf("unexpected destination static actor add after transfer: %+v", destinationActorAdd)
	}
	destinationActorInfo, err := worldproto.DecodeCharacterAdditionalInfo(decodeSingleFrame(t, moveOut[5]))
	if err != nil {
		t.Fatalf("decode destination static actor info after transfer: %v", err)
	}
	if destinationActorInfo.VID != uint32(actor.EntityID) || destinationActorInfo.Name != actor.Name {
		t.Fatalf("unexpected destination static actor info after transfer: %+v", destinationActorInfo)
	}
	destinationActorUpdate, err := worldproto.DecodeCharacterUpdate(decodeSingleFrame(t, moveOut[6]))
	if err != nil {
		t.Fatalf("decode destination static actor update after transfer: %v", err)
	}
	if destinationActorUpdate.VID != uint32(actor.EntityID) {
		t.Fatalf("unexpected destination static actor update after transfer: %+v", destinationActorUpdate)
	}
}

func TestGameRuntimeImportContentBundleQueuesSpawnGroupVisibilityForOnlinePlayers(t *testing.T) {
	store := loginticket.NewFileStore(t.TempDir())
	near := peerVisibilityCharacter("SpawnImportNear", 0x01035501, 0x02045501, 1800, 2900, 0, 101, 201)
	near.MapIndex = 42
	near.X = 1800
	near.Y = 2900
	far := peerVisibilityCharacter("SpawnImportFar", 0x01035502, 0x02045502, 9800, 9900, 0, 102, 202)
	far.MapIndex = 42
	far.X = 9800
	far.Y = 9900
	issuePeerTicket(t, store, "spawn-import-near", 0x55550101, near)
	issuePeerTicket(t, store, "spawn-import-far", 0x55550202, far)

	staticActorStore := staticstore.NewFileStore(t.TempDir() + "/static-actors.json")
	interactionStore := interactionstore.NewFileStore(t.TempDir() + "/interaction-definitions.json")
	runtime, err := newGameRuntimeWithAccountStoreAndContentStores(config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1", VisibilityMode: "radius", VisibilityRadius: 500, VisibilitySectorSize: 256}, store, nil, staticActorStore, interactionStore)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	nearFlow, nearEnter := enterGameWithLoginTicket(t, runtime.SessionFactory(), "spawn-import-near", 0x55550101)
	defer closeSessionFlow(t, nearFlow)
	if len(nearEnter) != 5 {
		t.Fatalf("expected near player base enter-game burst before spawn import, got %d frames", len(nearEnter))
	}
	farFlow, farEnter := enterGameWithLoginTicket(t, runtime.SessionFactory(), "spawn-import-far", 0x55550202)
	defer closeSessionFlow(t, farFlow)
	if len(farEnter) != 5 {
		t.Fatalf("expected far player base enter-game burst before spawn import, got %d frames", len(farEnter))
	}
	flushServerFrames(t, nearFlow)
	flushServerFrames(t, farFlow)

	_, err = runtime.ImportContentBundle(contentbundle.Bundle{SpawnGroups: []contentbundle.SpawnGroup{{
		Ref:           "practice.import_visible",
		Name:          "ImportedPracticeMob",
		MapIndex:      42,
		X:             1810,
		Y:             2910,
		RaceNum:       101,
		CombatProfile: string(worldruntime.StaticActorCombatProfileTrainingDummy),
	}}})
	if err != nil {
		t.Fatalf("import spawn-group content bundle: %v", err)
	}

	nearQueued := flushServerFrames(t, nearFlow)
	if len(nearQueued) != 3 {
		t.Fatalf("expected nearby online player to receive imported spawn actor bootstrap, got %d frames", len(nearQueued))
	}
	actorAdd, err := worldproto.DecodeCharacterAdd(decodeSingleFrame(t, nearQueued[0]))
	if err != nil {
		t.Fatalf("decode imported spawn actor add: %v", err)
	}
	if actorAdd.Type != 1 || actorAdd.X != 1810 || actorAdd.Y != 2910 {
		t.Fatalf("unexpected imported spawn actor add packet: %+v", actorAdd)
	}
	actorInfo, err := worldproto.DecodeCharacterAdditionalInfo(decodeSingleFrame(t, nearQueued[1]))
	if err != nil {
		t.Fatalf("decode imported spawn actor info: %v", err)
	}
	if actorInfo.VID != actorAdd.VID || actorInfo.Name != "ImportedPracticeMob" {
		t.Fatalf("unexpected imported spawn actor info packet: %+v add=%+v", actorInfo, actorAdd)
	}
	actorUpdate, err := worldproto.DecodeCharacterUpdate(decodeSingleFrame(t, nearQueued[2]))
	if err != nil {
		t.Fatalf("decode imported spawn actor update: %v", err)
	}
	if actorUpdate.VID != actorAdd.VID {
		t.Fatalf("unexpected imported spawn actor update packet: %+v add=%+v", actorUpdate, actorAdd)
	}
	if farQueued := flushServerFrames(t, farFlow); len(farQueued) != 0 {
		t.Fatalf("expected far online player outside radius to receive no imported spawn actor frames, got %d", len(farQueued))
	}
}

func TestGameRuntimeRejectsDuplicateStaticActorContentBundleWithoutMutatingRuntime(t *testing.T) {
	runtime, err := newGameRuntimeWithStoresAndTransferTriggers(
		config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"},
		loginticket.NewFileStore(t.TempDir()),
		accountstore.NewFileStore(t.TempDir()),
		staticstore.NewFileStore(t.TempDir()+"/static-actors.json"),
		interactionstore.NewFileStore(t.TempDir()+"/interaction-definitions.json"),
		nil,
	)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	_, err = runtime.ImportContentBundle(contentbundle.Bundle{
		StaticActors: []contentbundle.StaticActor{
			{Name: "VillageGuard", MapIndex: 42, X: 1700, Y: 2800, RaceNum: 20300, InteractionKind: interactionstore.KindTalk, InteractionRef: "npc:village_guard"},
			{Name: " VillageGuard ", MapIndex: 42, X: 1700, Y: 2800, RaceNum: 20300, InteractionKind: " talk ", InteractionRef: " npc:village_guard "},
		},
		InteractionDefinitions: []interactionstore.Definition{{Kind: interactionstore.KindTalk, Ref: "npc:village_guard", Text: "Keep your blade sharp."}},
	})
	if !errors.Is(err, contentbundle.ErrInvalidBundle) {
		t.Fatalf("expected duplicate static actor content bundle to fail closed, got %v", err)
	}
	if actors := runtime.StaticActors(); len(actors) != 0 {
		t.Fatalf("expected duplicate static actor import not to materialize runtime actors, got %+v", actors)
	}
	if definitions := runtime.InteractionDefinitions(); len(definitions) != 0 {
		t.Fatalf("expected duplicate static actor import not to persist interaction definitions, got %+v", definitions)
	}
}

func TestGameRuntimeImportsContentBundleCombatProfilesBeforeSpawnGroups(t *testing.T) {
	const profile = "practice_imported_wolf"
	worldruntime.UnregisterStaticActorCombatProfileForTest(profile)
	t.Cleanup(func() { worldruntime.UnregisterStaticActorCombatProfileForTest(profile) })

	runtime, err := newGameRuntimeWithStoresAndTransferTriggersAndItemStore(
		config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"},
		loginticket.NewFileStore(t.TempDir()),
		accountstore.NewFileStore(t.TempDir()),
		staticstore.NewFileStore(t.TempDir()+"/static-actors.json"),
		interactionstore.NewFileStore(t.TempDir()+"/interaction-definitions.json"),
		itemcatalog.NewFileStore(t.TempDir()+"/item-templates.json"),
		nil,
	)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	bundle := contentbundle.Bundle{
		SpawnGroups: []contentbundle.SpawnGroup{{
			Ref:           "practice.imported_wolf",
			Name:          "Practice Imported Wolf",
			MapIndex:      42,
			X:             1775,
			Y:             2875,
			RaceNum:       101,
			CombatProfile: profile,
		}},
		CombatProfiles: []worldruntime.StaticActorCombatProfileSnapshot{{
			Profile:               profile,
			MaxHP:                 24,
			DamagePerNormalAttack: 3,
			AttackValue:           7,
			DefenseValue:          4,
			Level:                 9,
			Rank:                  2,
			RespawnDelayMs:        1500,
			DeathReward:           worldruntime.StaticActorDeathReward{Experience: 15, Gold: 10, DropVnums: []uint32{27002, 27001}},
		}},
		ItemTemplates: rewardDropItemTemplates(27001, 27002),
	}

	imported, err := runtime.ImportContentBundle(bundle)
	if err != nil {
		t.Fatalf("import content bundle with authored combat profile: %v", err)
	}
	if !worldruntime.ValidStaticActorCombatProfile(profile) {
		t.Fatalf("expected imported combat profile %q to be registered before spawn import", profile)
	}
	actors := runtime.StaticActors()
	if len(actors) != 1 {
		t.Fatalf("expected one imported spawn actor, got %#v", actors)
	}
	if actors[0].CombatProfile != profile || actors[0].RewardExperience != 15 || actors[0].RewardGold != 10 || !reflect.DeepEqual(actors[0].RewardDropVnums, []uint32{27001, 27002}) {
		t.Fatalf("unexpected imported profile-backed spawn actor: %+v", actors[0])
	}
	if len(imported.CombatProfiles) != 1 || imported.CombatProfiles[0].Profile != profile {
		t.Fatalf("expected imported bundle to retain authored combat profile snapshot, got %#v", imported.CombatProfiles)
	}
}

func TestGameRuntimeRejectsDuplicateImportedCombatProfileSnapshotsWithoutMutatingRuntime(t *testing.T) {
	const profile = "practice_duplicate_import_wolf"
	worldruntime.UnregisterStaticActorCombatProfileForTest(profile)
	t.Cleanup(func() { worldruntime.UnregisterStaticActorCombatProfileForTest(profile) })

	runtime, err := newGameRuntimeWithStoresAndTransferTriggers(
		config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"},
		loginticket.NewFileStore(t.TempDir()),
		accountstore.NewFileStore(t.TempDir()),
		staticstore.NewFileStore(t.TempDir()+"/static-actors.json"),
		interactionstore.NewFileStore(t.TempDir()+"/interaction-definitions.json"),
		nil,
	)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	_, err = runtime.ImportContentBundle(contentbundle.Bundle{
		SpawnGroups: []contentbundle.SpawnGroup{{
			Ref:           "practice.duplicate_wolf",
			Name:          "Practice Duplicate Wolf",
			MapIndex:      42,
			X:             1775,
			Y:             2875,
			RaceNum:       101,
			CombatProfile: profile,
		}},
		CombatProfiles: []worldruntime.StaticActorCombatProfileSnapshot{
			{
				Profile:               profile,
				MaxHP:                 24,
				DamagePerNormalAttack: 3,
				AttackValue:           7,
				DefenseValue:          4,
				RespawnDelayMs:        1500,
			},
			{
				Profile:               profile,
				MaxHP:                 24,
				DamagePerNormalAttack: 3,
				AttackValue:           7,
				DefenseValue:          4,
				RespawnDelayMs:        1500,
			},
		},
	})
	if !errors.Is(err, contentbundle.ErrInvalidBundle) {
		t.Fatalf("expected duplicate imported combat profile snapshots to fail closed, got %v", err)
	}
	if worldruntime.ValidStaticActorCombatProfile(profile) {
		t.Fatalf("expected failed duplicate profile import not to leave profile %q registered", profile)
	}
	if actors := runtime.StaticActors(); len(actors) != 0 {
		t.Fatalf("expected failed duplicate profile import not to materialize actors, got %+v", actors)
	}
}

func TestGameRuntimeRejectsConflictingImportedCombatProfileSnapshot(t *testing.T) {
	const profile = "practice_conflicting_import_wolf"
	worldruntime.UnregisterStaticActorCombatProfileForTest(profile)
	t.Cleanup(func() { worldruntime.UnregisterStaticActorCombatProfileForTest(profile) })
	if !worldruntime.RegisterStaticActorCombatProfile(profile, worldruntime.StaticActorCombatProfileDefaults{
		MaxHP:                 24,
		DamagePerNormalAttack: 3,
		AttackValue:           7,
		DefenseValue:          4,
		RespawnDelay:          1500 * time.Millisecond,
	}) {
		t.Fatalf("expected local combat profile %q to register", profile)
	}

	runtime, err := newGameRuntimeWithStoresAndTransferTriggers(
		config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"},
		loginticket.NewFileStore(t.TempDir()),
		accountstore.NewFileStore(t.TempDir()),
		staticstore.NewFileStore(t.TempDir()+"/static-actors.json"),
		interactionstore.NewFileStore(t.TempDir()+"/interaction-definitions.json"),
		nil,
	)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	_, err = runtime.ImportContentBundle(contentbundle.Bundle{
		SpawnGroups: []contentbundle.SpawnGroup{{
			Ref:           "practice.conflicting_wolf",
			Name:          "Practice Conflicting Wolf",
			MapIndex:      42,
			X:             1775,
			Y:             2875,
			RaceNum:       101,
			CombatProfile: profile,
		}},
		CombatProfiles: []worldruntime.StaticActorCombatProfileSnapshot{{
			Profile:               profile,
			MaxHP:                 30,
			DamagePerNormalAttack: 3,
			AttackValue:           7,
			DefenseValue:          4,
			RespawnDelayMs:        1500,
		}},
	})
	if !errors.Is(err, contentbundle.ErrInvalidBundle) {
		t.Fatalf("expected conflicting imported combat profile snapshot to fail closed, got %v", err)
	}
	actors := runtime.StaticActors()
	if len(actors) != 0 {
		t.Fatalf("expected failed conflicting profile import not to materialize actors, got %+v", actors)
	}
	defaults, ok := worldruntime.BootstrapStaticActorCombatProfileDefaults(profile)
	if !ok || defaults.MaxHP != 24 || defaults.DamagePerNormalAttack != 3 {
		t.Fatalf("expected local combat profile defaults to remain unchanged, got defaults=%+v ok=%v", defaults, ok)
	}
}

func TestGameRuntimeRollsBackImportedCombatProfilesWhenStaticActorPersistenceFails(t *testing.T) {
	const profile = "practice_import_rollback_wolf"
	worldruntime.UnregisterStaticActorCombatProfileForTest(profile)
	t.Cleanup(func() { worldruntime.UnregisterStaticActorCombatProfileForTest(profile) })

	staticActorStore := staticstore.NewFileStore(t.TempDir() + "/static-actors.json")
	interactionStore := interactionstore.NewFileStore(t.TempDir() + "/interaction-definitions.json")
	runtime, err := newGameRuntimeWithStoresAndTransferTriggers(
		config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"},
		loginticket.NewFileStore(t.TempDir()),
		accountstore.NewFileStore(t.TempDir()),
		staticActorStore,
		interactionStore,
		nil,
	)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	if worldruntime.ValidStaticActorCombatProfile(profile) {
		t.Fatalf("expected imported profile %q to start unregistered", profile)
	}

	runtime.staticStore = &failingStaticActorStore{}
	_, err = runtime.ImportContentBundle(contentbundle.Bundle{
		SpawnGroups: []contentbundle.SpawnGroup{{
			Ref:           "practice.rollback_wolf",
			Name:          "Practice Rollback Wolf",
			MapIndex:      42,
			X:             1775,
			Y:             2875,
			RaceNum:       101,
			CombatProfile: profile,
		}},
		CombatProfiles: []worldruntime.StaticActorCombatProfileSnapshot{{
			Profile:               profile,
			MaxHP:                 24,
			DamagePerNormalAttack: 3,
			AttackValue:           7,
			DefenseValue:          4,
			RespawnDelayMs:        1500,
		}},
	})
	if err == nil {
		t.Fatal("expected content bundle import to fail when static actor persistence fails")
	}
	if worldruntime.ValidStaticActorCombatProfile(profile) {
		t.Fatalf("expected failed content import to roll back newly registered profile %q", profile)
	}
}

func TestGameRuntimeFailedContentBundleImportDoesNotLeakSpawnVisibilityFrames(t *testing.T) {
	store := loginticket.NewFileStore(t.TempDir())
	near := peerVisibilityCharacter("SpawnImportRollbackNear", 0x01035521, 3, 1800, 2900, 0, 101, 201)
	near.MapIndex = 42
	near.X = 1800
	near.Y = 2900
	issuePeerTicket(t, store, "spawn-import-rollback-near", 0x55552121, near)

	staticActorStore := staticstore.NewFileStore(t.TempDir() + "/static-actors.json")
	interactionStore := interactionstore.NewFileStore(t.TempDir() + "/interaction-definitions.json")
	runtime, err := newGameRuntimeWithAccountStoreAndContentStores(config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1", VisibilityMode: "radius", VisibilityRadius: 500, VisibilitySectorSize: 256}, store, nil, staticActorStore, interactionStore)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	flow, enterOut := enterGameWithLoginTicket(t, runtime.SessionFactory(), "spawn-import-rollback-near", 0x55552121)
	defer closeSessionFlow(t, flow)
	if len(enterOut) != 5 {
		t.Fatalf("expected base enter-game burst before failed spawn import, got %d frames", len(enterOut))
	}
	flushServerFrames(t, flow)

	_, err = runtime.ImportContentBundle(contentbundle.Bundle{SpawnGroups: []contentbundle.SpawnGroup{
		{
			Ref:           "practice.rollback_visible_first",
			Name:          "RollbackVisiblePracticeMobFirst",
			MapIndex:      42,
			X:             1810,
			Y:             2910,
			RaceNum:       101,
			CombatProfile: string(worldruntime.StaticActorCombatProfileTrainingDummy),
		},
		{
			Ref:           "practice.rollback_visible_second",
			Name:          "RollbackVisiblePracticeMobSecond",
			MapIndex:      42,
			X:             1820,
			Y:             2920,
			RaceNum:       101,
			CombatProfile: string(worldruntime.StaticActorCombatProfileTrainingDummy),
		},
	}})
	if err == nil {
		t.Fatal("expected content bundle import to fail when a later spawn actor conflicts with a live player VID")
	}
	if queued := flushServerFrames(t, flow); len(queued) != 0 {
		t.Fatalf("expected failed content import not to leak queued spawn visibility frames, got %d", len(queued))
	}
	if actors := runtime.StaticActors(); len(actors) != 0 {
		t.Fatalf("expected failed content import not to materialize runtime static actors, got %+v", actors)
	}
}

func TestGameRuntimeUpdateSpawnGroupActorSnapshotKeepsCombatLevelAndRank(t *testing.T) {
	const profile = "practice_spawn_update_ranked_wolf"
	worldruntime.UnregisterStaticActorCombatProfileForTest(profile)
	t.Cleanup(func() { worldruntime.UnregisterStaticActorCombatProfileForTest(profile) })
	if !worldruntime.RegisterStaticActorCombatProfile(profile, worldruntime.StaticActorCombatProfileDefaults{
		MaxHP:        24,
		AttackValue:  7,
		Level:        19,
		Rank:         4,
		RespawnDelay: 1500 * time.Millisecond,
	}) {
		t.Fatalf("expected combat profile %q to register", profile)
	}

	runtime, err := newGameRuntimeWithStoresAndTransferTriggers(
		config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"},
		loginticket.NewFileStore(t.TempDir()),
		accountstore.NewFileStore(t.TempDir()),
		staticstore.NewFileStore(t.TempDir()+"/static-actors.json"),
		interactionstore.NewFileStore(t.TempDir()+"/interaction-definitions.json"),
		nil,
	)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}

	if _, err := runtime.ImportContentBundle(contentbundle.Bundle{SpawnGroups: []contentbundle.SpawnGroup{{
		Ref:           "practice.spawn_update_ranked",
		Name:          "Ranked Practice Mob",
		MapIndex:      42,
		X:             1700,
		Y:             2800,
		RaceNum:       20350,
		CombatProfile: profile,
	}}}); err != nil {
		t.Fatalf("import ranked spawn group: %v", err)
	}
	actors := runtime.StaticActors()
	if len(actors) != 1 {
		t.Fatalf("expected one runtime actor after import, got %d", len(actors))
	}
	if actors[0].CombatLevel != 19 || actors[0].CombatRank != 4 {
		t.Fatalf("expected imported actor snapshot to expose combat level/rank, got %+v", actors[0])
	}

	updated, ok := runtime.UpdateStaticActor(actors[0].EntityID, "Ranked Practice Mob Moved", 42, 1800, 2900, 20351)
	if !ok {
		t.Fatal("expected spawn-backed actor update to succeed")
	}
	if updated.CombatProfile != profile || updated.CombatLevel != 19 || updated.CombatRank != 4 {
		t.Fatalf("expected updated spawn actor snapshot to preserve combat profile level/rank, got %+v", updated)
	}
	refreshed := runtime.StaticActors()
	if len(refreshed) != 1 || refreshed[0].CombatLevel != 19 || refreshed[0].CombatRank != 4 {
		t.Fatalf("expected runtime actor snapshots to preserve combat level/rank after update, got %+v", refreshed)
	}
}

func TestGameRuntimeUpdateSpawnGroupActorPreservesRewardDescriptor(t *testing.T) {
	store := loginticket.NewFileStore(t.TempDir())
	accounts := accountstore.NewFileStore(t.TempDir())
	staticActorStore := staticstore.NewFileStore(t.TempDir() + "/static-actors.json")
	interactionStore := interactionstore.NewFileStore(t.TempDir() + "/interaction-definitions.json")
	runtime, err := newGameRuntimeWithStoresAndTransferTriggersAndItemStore(
		config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"},
		store,
		accounts,
		staticActorStore,
		interactionStore,
		itemcatalog.NewFileStore(t.TempDir()+"/item-templates.json"),
		nil,
	)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}

	imported, err := runtime.ImportContentBundle(contentbundle.Bundle{
		SpawnGroups: []contentbundle.SpawnGroup{{
			Ref:              "practice.mob_alpha",
			Name:             "Practice Mob Alpha",
			MapIndex:         42,
			X:                1700,
			Y:                2800,
			RaceNum:          20350,
			CombatProfile:    worldruntime.StaticActorCombatProfilePracticeMob,
			RewardExperience: 125,
			RewardGold:       75,
			RewardDropVnums:  []uint32{3001, 3002},
		}},
		ItemTemplates: rewardDropItemTemplates(3001, 3002),
	})
	if err != nil {
		t.Fatalf("import spawn group bundle: %v", err)
	}
	if len(imported.SpawnGroups) != 1 {
		t.Fatalf("expected one imported spawn group, got %d", len(imported.SpawnGroups))
	}

	actors := runtime.StaticActors()
	if len(actors) != 1 {
		t.Fatalf("expected one runtime actor after import, got %d", len(actors))
	}
	actor := actors[0]
	updated, ok := runtime.UpdateStaticActor(actor.EntityID, "Practice Mob Alpha Moved", 43, 1800, 2900, 20351)
	if !ok {
		t.Fatal("expected spawn-backed actor update to succeed")
	}
	if updated.SpawnGroupRef != "practice.mob_alpha" {
		t.Fatalf("expected spawn group ref to be preserved, got %q", updated.SpawnGroupRef)
	}
	if updated.CombatProfile != worldruntime.StaticActorCombatProfilePracticeMob {
		t.Fatalf("expected combat profile to be preserved, got %q", updated.CombatProfile)
	}
	if updated.RewardExperience != 125 || updated.RewardGold != 75 || !reflect.DeepEqual(updated.RewardDropVnums, []uint32{3001, 3002}) {
		t.Fatalf("expected reward descriptor to be preserved in update snapshot, got %+v", updated)
	}

	exported, err := runtime.ExportContentBundle()
	if err != nil {
		t.Fatalf("export content bundle: %v", err)
	}
	if len(exported.SpawnGroups) != 1 {
		t.Fatalf("expected one exported spawn group, got %d", len(exported.SpawnGroups))
	}
	spawn := exported.SpawnGroups[0]
	if spawn.Ref != "practice.mob_alpha" || spawn.Name != "Practice Mob Alpha Moved" || spawn.MapIndex != 43 || spawn.X != 1800 || spawn.Y != 2900 || spawn.RaceNum != 20351 {
		t.Fatalf("unexpected exported moved spawn group: %+v", spawn)
	}
	if spawn.RewardExperience != 125 || spawn.RewardGold != 75 || !reflect.DeepEqual(spawn.RewardDropVnums, []uint32{3001, 3002}) {
		t.Fatalf("expected exported reward descriptor to be preserved, got %+v", spawn)
	}
}

func TestSharedWorldRegistryRegisterGroundItemRejectsExistingVID(t *testing.T) {
	registry := newSharedWorldRegistry()
	owner := peerVisibilityCharacter("DropOwner", 0x01030190, 0x02040190, 1200, 2200, 0, 101, 201)
	ownerID, _ := registry.Join(owner, newPendingServerFrames(), nil)

	item := inventory.ItemInstance{ID: 0x30010001, Vnum: 3001, Count: 1}
	if !registry.RegisterGroundItem(ownerID, "drop-owner", owner, 0x07000001, item) {
		t.Fatal("expected first ground item registration to succeed")
	}
	if !registry.GroundItemExists(0x07000001) {
		t.Fatal("expected first ground item to remain registered")
	}

	duplicate := inventory.ItemInstance{ID: 0x30020001, Vnum: 3002, Count: 1}
	if registry.RegisterGroundItem(ownerID, "drop-owner", owner, 0x07000001, duplicate) {
		t.Fatal("expected duplicate ground item VID registration to fail closed")
	}
	stored, ok := registry.GroundItemVisibleTo(ownerID, owner, 0x07000001)
	if !ok {
		t.Fatal("expected original ground item to remain visible after duplicate rejection")
	}
	if stored.Vnum != item.Vnum || stored.Count != item.Count {
		t.Fatalf("expected original ground item to be preserved, got %+v", stored)
	}
}

