func TestGameSessionFlowRejectsInfoChatAfterDelayedRetaliationReachesOwnerHPFloor(t *testing.T) {
	_, ownerFlow, watcherFlow, targetVID, owner, advance := setupPracticeMobStaticActorZeroHPOwnerRecipientTest(t)
	defer closeSessionFlow(t, ownerFlow)
	defer closeSessionFlow(t, watcherFlow)

	drivePracticeMobOwnerToZeroHPAfterDelayedRetaliation(t, ownerFlow, watcherFlow, targetVID, owner.VID, advance)

	infoOut, err := ownerFlow.HandleClientFrame(decodeSingleFrame(t, chatproto.EncodeClientChat(chatproto.ClientChatPacket{Type: chatproto.ChatTypeInfo, Message: "mensaje info"})))
	if err != nil {
		t.Fatalf("unexpected zero-HP owner info chat error: %v", err)
	}
	if len(infoOut) != 0 {
		t.Fatalf("expected zero-HP owner info chat to fail closed, got %d frames", len(infoOut))
	}
	if queued := flushServerFrames(t, watcherFlow); len(queued) != 0 {
		t.Fatalf("expected zero-HP owner info chat to queue no peer frames, got %d", len(queued))
	}
}

func TestGameSessionFlowRejectsNonTalkingSlashRestartAfterDelayedRetaliationReachesOwnerHPFloor(t *testing.T) {
	runtime, ownerFlow, watcherFlow, targetVID, owner, advance := setupPracticeMobStaticActorZeroHPOwnerRecipientTest(t)
	defer closeSessionFlow(t, ownerFlow)
	defer closeSessionFlow(t, watcherFlow)

	drivePracticeMobOwnerToZeroHPAfterDelayedRetaliation(t, ownerFlow, watcherFlow, targetVID, owner.VID, advance)

	restartOut, err := ownerFlow.HandleClientFrame(decodeSingleFrame(t, chatproto.EncodeClientChat(chatproto.ClientChatPacket{Type: chatproto.ChatTypeInfo, Message: "/restart_here"})))
	if err != nil {
		t.Fatalf("unexpected non-talking /restart_here error: %v", err)
	}
	if len(restartOut) != 0 {
		t.Fatalf("expected non-talking /restart_here to fail closed at zero HP, got %d frames", len(restartOut))
	}
	if queued := flushServerFrames(t, watcherFlow); len(queued) != 0 {
		t.Fatalf("expected non-talking /restart_here to queue no peer frames, got %d", len(queued))
	}

	connected := runtime.ConnectedCharacters()
	var ownerSnapshot *ConnectedCharacterSnapshot
	for i := range connected {
		if connected[i].Name == owner.Name {
			ownerSnapshot = &connected[i]
			break
		}
	}
	if ownerSnapshot == nil || !ownerSnapshot.Dead {
		t.Fatalf("expected non-talking /restart_here to leave owner dead, got %+v in %+v", ownerSnapshot, connected)
	}
}

func TestGameSessionFlowRejectsQuickslotMutationsAfterDelayedRetaliationReachesOwnerHPFloor(t *testing.T) {
	_, ownerFlow, watcherFlow, targetVID, owner, advance := setupPracticeMobStaticActorZeroHPOwnerRecipientTest(t)
	defer closeSessionFlow(t, ownerFlow)
	defer closeSessionFlow(t, watcherFlow)

	drivePracticeMobOwnerToZeroHPAfterDelayedRetaliation(t, ownerFlow, watcherFlow, targetVID, owner.VID, advance)

	quickslotAttempts := []struct {
		name  string
		frame []byte
	}{
		{
			name:  "add",
			frame: quickslotproto.EncodeClientAdd(quickslotproto.ClientAddPacket{Position: 3, Slot: quickslotproto.Slot{Type: quickslotproto.TypeItem, Position: 0}}),
		},
		{
			name:  "del",
			frame: quickslotproto.EncodeClientDel(quickslotproto.ClientDelPacket{Position: 3}),
		},
		{
			name:  "swap",
			frame: quickslotproto.EncodeClientSwap(quickslotproto.ClientSwapPacket{Position: 3, TargetPosition: 4}),
		},
	}
	for _, attempt := range quickslotAttempts {
		out, err := ownerFlow.HandleClientFrame(decodeSingleFrame(t, attempt.frame))
		if err != nil {
			t.Fatalf("unexpected zero-HP owner quickslot %s error: %v", attempt.name, err)
		}
		if len(out) != 0 {
			t.Fatalf("expected zero-HP owner quickslot %s to fail closed, got %d frames", attempt.name, len(out))
		}
		if queued := flushServerFrames(t, watcherFlow); len(queued) != 0 {
			t.Fatalf("expected zero-HP owner quickslot %s to queue no peer frames, got %d", attempt.name, len(queued))
		}
	}
}

