func TestGameRuntimeBroadcastNoticeSkipsZeroHPOwnerAfterDelayedRetaliationReachesOwnerHPFloor(t *testing.T) {
	store := loginticket.NewFileStore(t.TempDir())
	owner := peerVisibilityCharacter("PeerOne", 0x01030101, 0x02040101, 1100, 2100, 0, 101, 201)
	owner.Points[bootstrapPlayerPointValueIndex] = 2
	watcher := peerVisibilityCharacter("PeerTwo", 0x01030102, 0x02040102, 1300, 2300, 2, 102, 202)
	issuePeerTicket(t, store, "peer-one", 0x11111111, owner)
	issuePeerTicket(t, store, "peer-two", 0x22222222, watcher)

	staticActorStore := staticstore.NewFileStore(t.TempDir() + "/static-actors.json")
	interactionStore := interactionstore.NewFileStore(t.TempDir() + "/interaction-definitions.json")
	runtime, err := newGameRuntimeWithAccountStoreAndContentStores(config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"}, store, nil, staticActorStore, interactionStore)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	currentTime := time.Unix(1700000470, 0)
	runtime.now = func() time.Time { return currentTime }
	bundle := contentbundle.Bundle{SpawnGroups: []contentbundle.SpawnGroup{{
		Ref:           "practice.mob_alpha",
		Name:          "PracticeMobAlpha",
		MapIndex:      bootstrapMapIndex,
		X:             1200,
		Y:             2200,
		RaceNum:       101,
		CombatProfile: string(worldruntime.StaticActorCombatProfileTrainingDummy),
	}}}
	if _, err := runtime.ImportContentBundle(bundle); err != nil {
		t.Fatalf("import content spawn-group bundle: %v", err)
	}
	actors := runtime.StaticActors()
	if len(actors) != 1 {
		t.Fatalf("expected 1 runtime practice-mob actor after import, got %#v", actors)
	}
	targetVID := uint32(actors[0].EntityID)

	ownerFlow, ownerEnter := enterGameWithLoginTicket(t, runtime.SessionFactory(), "peer-one", 0x11111111)
	if len(ownerEnter) != 8 {
		t.Fatalf("expected 8 bootstrap frames for owner with visible content practice mob, got %d", len(ownerEnter))
	}
	defer closeSessionFlow(t, ownerFlow)
	watcherFlow, watcherEnter := enterGameWithLoginTicket(t, runtime.SessionFactory(), "peer-two", 0x22222222)
	if len(watcherEnter) != 11 {
		t.Fatalf("expected 11 bootstrap frames for watcher with visible owner and content practice mob, got %d", len(watcherEnter))
	}
	defer closeSessionFlow(t, watcherFlow)
	if queued := flushServerFrames(t, ownerFlow); len(queued) != 3 {
		t.Fatalf("expected 3 queued peer-visibility frames for owner after watcher joins, got %d", len(queued))
	}

	selectOut, err := ownerFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected target-selection error before zero-HP owner server-notice skip after delayed retaliation: %v", err)
	}
	if len(selectOut) != 1 {
		t.Fatalf("expected 1 target-selection frame before zero-HP owner server-notice skip after delayed retaliation, got %d", len(selectOut))
	}

	attackOut, err := ownerFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{
		AttackType: combatproto.ClientAttackTypeNormal,
		TargetVID:  targetVID,
	})))
	if err != nil {
		t.Fatalf("unexpected attack error before zero-HP owner server-notice skip after delayed retaliation: %v", err)
	}
	if len(attackOut) != 2 {
		t.Fatalf("expected target refresh plus first point-loss retaliation before zero-HP owner server-notice skip after delayed retaliation, got %d frames", len(attackOut))
	}

	currentTime = currentTime.Add(time.Second)
	queued := flushServerFrames(t, ownerFlow)
	if len(queued) != 3 {
		t.Fatalf("expected delayed retaliation point-loss, self dead, and clear-target frames before zero-HP owner server-notice skip after delayed retaliation, got %d frames", len(queued))
	}
	pointChange, err := worldproto.DecodePlayerPointChange(decodeSingleFrame(t, queued[0]))
	if err != nil {
		t.Fatalf("decode delayed retaliation point-change before zero-HP owner server-notice skip after delayed retaliation: %v", err)
	}
	if pointChange.Value != 0 {
		t.Fatalf("expected delayed retaliation beat to reach owner HP floor before zero-HP owner server-notice skip after delayed retaliation, got %+v", pointChange)
	}
	watcherQueued := flushServerFrames(t, watcherFlow)
	if len(watcherQueued) != 1 {
		t.Fatalf("expected delayed retaliation reaching owner HP floor to queue 1 visible-peer DEAD frame before zero-HP owner server-notice skip, got %d", len(watcherQueued))
	}
	dead, err := worldproto.DecodeDead(decodeSingleFrame(t, watcherQueued[0]))
	if err != nil {
		t.Fatalf("decode visible-peer dead frame before zero-HP owner server-notice skip after delayed retaliation: %v", err)
	}
	if dead.VID != owner.VID {
		t.Fatalf("expected visible-peer DEAD(owner_vid) before zero-HP owner server-notice skip after delayed retaliation, got %+v", dead)
	}

	delivered := runtime.BroadcastNotice("server maintenance after floor")
	if delivered != 1 {
		t.Fatalf("expected server notice to be queued for only the live watcher after delayed retaliation reached owner HP floor, got %d deliveries", delivered)
	}
	if queued := flushServerFrames(t, ownerFlow); len(queued) != 0 {
		t.Fatalf("expected zero-HP owner server-notice skip after delayed retaliation not to queue notice delivery, got %d", len(queued))
	}
	noticeFrames := flushServerFrames(t, watcherFlow)
	if len(noticeFrames) != 1 {
		t.Fatalf("expected live watcher to receive 1 queued server notice after delayed retaliation reached owner HP floor, got %d", len(noticeFrames))
	}
	notice, err := chatproto.DecodeChatDelivery(decodeSingleFrame(t, noticeFrames[0]))
	if err != nil {
		t.Fatalf("decode queued server notice after delayed retaliation reached owner HP floor: %v", err)
	}
	if notice.Type != chatproto.ChatTypeNotice || notice.VID != 0 || notice.Message != "server maintenance after floor" {
		t.Fatalf("unexpected queued server notice after delayed retaliation reached owner HP floor: %+v", notice)
	}
}

func TestSharedWorldRegistryEnqueueToVisibleSessionsSkipsZeroHPOwnerRecipient(t *testing.T) {
	registry := newSharedWorldRegistry()
	origin := peerVisibilityCharacter("Origin", 0x01030110, 0x02040110, 1100, 2100, 0, 101, 201)
	deadRecipient := peerVisibilityCharacter("DeadRecipient", 0x01030111, 0x02040111, 1200, 2200, 0, 102, 202)
	liveRecipient := peerVisibilityCharacter("LiveRecipient", 0x01030112, 0x02040112, 1300, 2300, 0, 103, 203)

	originPending := newPendingServerFrames()
	originID, _ := registry.Join(origin, originPending, nil)
	if originID == 0 {
		t.Fatal("expected origin join to succeed")
	}
	deadPending := newPendingServerFrames()
	deadID, _ := registry.Join(deadRecipient, deadPending, nil)
	if deadID == 0 {
		t.Fatal("expected dead-recipient join to succeed")
	}
	livePending := newPendingServerFrames()
	liveID, _ := registry.Join(liveRecipient, livePending, nil)
	if liveID == 0 {
		t.Fatal("expected live-recipient join to succeed")
	}

	_ = originPending.flush()
	_ = deadPending.flush()
	_ = livePending.flush()

	deadRecipient.Points[bootstrapPlayerPointValueIndex] = 0
	registry.UpdateCharacter(deadID, deadRecipient)

	frames := [][]byte{chatproto.EncodeChatDelivery(chatproto.ChatDeliveryPacket{
		Type:    chatproto.ChatTypeTalking,
		VID:     origin.VID,
		Empire:  origin.Empire,
		Message: "visible helper delivery",
	})}
	registry.EnqueueToVisibleSessions(originID, origin, frames)

	if queued := originPending.flush(); len(queued) != 0 {
		t.Fatalf("expected generic visible-session fanout not to echo back to origin, got %d queued frames", len(queued))
	}
	if queued := deadPending.flush(); len(queued) != 0 {
		t.Fatalf("expected generic visible-session fanout to skip zero-HP recipient, got %d queued frames", len(queued))
	}
	liveQueued := livePending.flush()
	if len(liveQueued) != 1 {
		t.Fatalf("expected generic visible-session fanout to keep live recipient delivery, got %d queued frames", len(liveQueued))
	}
	chat, err := chatproto.DecodeChatDelivery(decodeSingleFrame(t, liveQueued[0]))
	if err != nil {
		t.Fatalf("decode live generic visible-session fanout delivery: %v", err)
	}
	if chat.Type != chatproto.ChatTypeTalking || chat.VID != origin.VID || chat.Message != "visible helper delivery" {
		t.Fatalf("unexpected live generic visible-session fanout delivery: %+v", chat)
	}
}

