func TestGameRuntimeTransferCharacterReturnsStructuredResult(t *testing.T) {
	store := loginticket.NewFileStore(t.TempDir())
	peerOne := peerVisibilityCharacter("PeerOne", 0x01030101, 0x02040101, 1100, 2100, 0, 101, 201)
	peerTwo := peerVisibilityCharacter("PeerTwo", 0x01030102, 0x02040102, 1300, 2300, 2, 102, 202)
	peerThree := peerVisibilityCharacter("PeerThree", 0x01030103, 0x02040103, 1500, 2500, 1, 103, 203)
	peerThree.MapIndex = 42
	issuePeerTicket(t, store, "peer-one", 0x11111111, peerOne)
	issuePeerTicket(t, store, "peer-two", 0x22222222, peerTwo)
	issuePeerTicket(t, store, "peer-three", 0x33333333, peerThree)

	runtime, err := newGameRuntimeWithAccountStore(config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"}, store, nil)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	blacksmith, ok := runtime.RegisterStaticActor("Blacksmith", bootstrapMapIndex, 1050, 2050, 20301)
	if !ok {
		t.Fatal("expected bootstrap static actor registration to succeed")
	}
	guard, ok := runtime.RegisterStaticActor("VillageGuard", 42, 1700, 2800, 20300)
	if !ok {
		t.Fatal("expected destination static actor registration to succeed")
	}
	factory := runtime.SessionFactory()

	flowOne, _ := enterGameWithLoginTicket(t, factory, "peer-one", 0x11111111)
	flowTwo, _ := enterGameWithLoginTicket(t, factory, "peer-two", 0x22222222)
	flowThree, _ := enterGameWithLoginTicket(t, factory, "peer-three", 0x33333333)
	_ = flushServerFrames(t, flowOne)
	_ = flushServerFrames(t, flowTwo)
	_ = flushServerFrames(t, flowThree)

	result, ok := runtime.TransferCharacter("PeerTwo", 42, 1700, 2800)
	if !ok {
		t.Fatal("expected transfer to succeed")
	}
	if !result.Applied {
		t.Fatal("expected transfer result to be marked applied")
	}
	if result.Character.Name != "PeerTwo" || result.Character.MapIndex != bootstrapMapIndex || result.Character.X != 1300 || result.Character.Y != 2300 {
		t.Fatalf("unexpected source transfer snapshot: %+v", result.Character)
	}
	if result.Target.Name != "PeerTwo" || result.Target.MapIndex != 42 || result.Target.X != 1700 || result.Target.Y != 2800 {
		t.Fatalf("unexpected target transfer snapshot: %+v", result.Target)
	}
	if len(result.CurrentVisiblePeers) != 1 || result.CurrentVisiblePeers[0].Name != "PeerOne" {
		t.Fatalf("unexpected current visible peers: %+v", result.CurrentVisiblePeers)
	}
	if len(result.TargetVisiblePeers) != 1 || result.TargetVisiblePeers[0].Name != "PeerThree" {
		t.Fatalf("unexpected target visible peers: %+v", result.TargetVisiblePeers)
	}
	if len(result.RemovedVisiblePeers) != 1 || result.RemovedVisiblePeers[0].Name != "PeerOne" {
		t.Fatalf("unexpected removed visible peers: %+v", result.RemovedVisiblePeers)
	}
	if len(result.AddedVisiblePeers) != 1 || result.AddedVisiblePeers[0].Name != "PeerThree" {
		t.Fatalf("unexpected added visible peers: %+v", result.AddedVisiblePeers)
	}
	if len(result.CurrentVisibleStaticActors) != 1 || result.CurrentVisibleStaticActors[0].EntityID != blacksmith.EntityID || result.CurrentVisibleStaticActors[0].Name != "Blacksmith" {
		t.Fatalf("unexpected current visible static actors: %+v", result.CurrentVisibleStaticActors)
	}
	if len(result.TargetVisibleStaticActors) != 1 || result.TargetVisibleStaticActors[0].EntityID != guard.EntityID || result.TargetVisibleStaticActors[0].Name != "VillageGuard" {
		t.Fatalf("unexpected target visible static actors: %+v", result.TargetVisibleStaticActors)
	}
	if len(result.RemovedVisibleStaticActors) != 1 || result.RemovedVisibleStaticActors[0].EntityID != blacksmith.EntityID || result.RemovedVisibleStaticActors[0].Name != "Blacksmith" {
		t.Fatalf("unexpected removed visible static actors: %+v", result.RemovedVisibleStaticActors)
	}
	if len(result.AddedVisibleStaticActors) != 1 || result.AddedVisibleStaticActors[0].EntityID != guard.EntityID || result.AddedVisibleStaticActors[0].Name != "VillageGuard" {
		t.Fatalf("unexpected added visible static actors: %+v", result.AddedVisibleStaticActors)
	}
	if len(result.MapOccupancyChanges) != 2 || result.MapOccupancyChanges[0].MapIndex != bootstrapMapIndex || result.MapOccupancyChanges[0].BeforeCount != 2 || result.MapOccupancyChanges[0].AfterCount != 1 || result.MapOccupancyChanges[1].MapIndex != 42 || result.MapOccupancyChanges[1].BeforeCount != 1 || result.MapOccupancyChanges[1].AfterCount != 2 {
		t.Fatalf("unexpected map occupancy changes: %+v", result.MapOccupancyChanges)
	}
	if len(result.BeforeMapOccupancy) != 2 {
		t.Fatalf("expected 2 before-map occupancy snapshots, got %d", len(result.BeforeMapOccupancy))
	}
	if result.BeforeMapOccupancy[0].MapIndex != bootstrapMapIndex || result.BeforeMapOccupancy[0].CharacterCount != 2 || len(result.BeforeMapOccupancy[0].Characters) != 2 || result.BeforeMapOccupancy[0].StaticActorCount != 1 || len(result.BeforeMapOccupancy[0].StaticActors) != 1 || result.BeforeMapOccupancy[0].StaticActors[0].EntityID != blacksmith.EntityID || result.BeforeMapOccupancy[0].StaticActors[0].Name != "Blacksmith" {
		t.Fatalf("unexpected source before-map occupancy snapshot: %+v", result.BeforeMapOccupancy[0])
	}
	if result.BeforeMapOccupancy[1].MapIndex != 42 || result.BeforeMapOccupancy[1].CharacterCount != 1 || len(result.BeforeMapOccupancy[1].Characters) != 1 || result.BeforeMapOccupancy[1].StaticActorCount != 1 || len(result.BeforeMapOccupancy[1].StaticActors) != 1 || result.BeforeMapOccupancy[1].StaticActors[0].EntityID != guard.EntityID || result.BeforeMapOccupancy[1].StaticActors[0].Name != "VillageGuard" {
		t.Fatalf("unexpected destination before-map occupancy snapshot: %+v", result.BeforeMapOccupancy[1])
	}
	if len(result.AfterMapOccupancy) != 2 {
		t.Fatalf("expected 2 after-map occupancy snapshots, got %d", len(result.AfterMapOccupancy))
	}
	if result.AfterMapOccupancy[0].MapIndex != bootstrapMapIndex || result.AfterMapOccupancy[0].CharacterCount != 1 || len(result.AfterMapOccupancy[0].Characters) != 1 || result.AfterMapOccupancy[0].StaticActorCount != 1 || len(result.AfterMapOccupancy[0].StaticActors) != 1 || result.AfterMapOccupancy[0].StaticActors[0].EntityID != blacksmith.EntityID || result.AfterMapOccupancy[0].StaticActors[0].Name != "Blacksmith" {
		t.Fatalf("unexpected source after-map occupancy snapshot: %+v", result.AfterMapOccupancy[0])
	}
	if result.AfterMapOccupancy[1].MapIndex != 42 || result.AfterMapOccupancy[1].CharacterCount != 2 || len(result.AfterMapOccupancy[1].Characters) != 2 || result.AfterMapOccupancy[1].StaticActorCount != 1 || len(result.AfterMapOccupancy[1].StaticActors) != 1 || result.AfterMapOccupancy[1].StaticActors[0].EntityID != guard.EntityID || result.AfterMapOccupancy[1].StaticActors[0].Name != "VillageGuard" {
		t.Fatalf("unexpected destination after-map occupancy snapshot: %+v", result.AfterMapOccupancy[1])
	}

	if snapshots := runtime.ConnectedCharacters(); len(snapshots) != 3 || snapshots[2].Name != "PeerTwo" || snapshots[2].MapIndex != 42 || snapshots[2].X != 1700 || snapshots[2].Y != 2800 {
		t.Fatalf("expected connected character snapshot to reflect transfer, got %+v", snapshots)
	}
}

func TestGameRuntimeStaticActorSnapshotsMarkDeadTrainingDummy(t *testing.T) {
	store := loginticket.NewFileStore(t.TempDir())
	killer := peerVisibilityCharacter("Killer", 0x01030101, 0x02040101, 1100, 2100, 0, 101, 201)
	issuePeerTicket(t, store, "killer", 0x11111111, killer)

	runtime, err := newGameRuntimeWithAccountStore(config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"}, store, nil)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	currentTime := time.Unix(1700000305, 0)
	runtime.now = func() time.Time { return currentTime }
	actor, ok := runtime.sharedWorld.RegisterStaticActorWithCombatKind(0, "TrainingDummy", bootstrapMapIndex, 1200, 2200, 20350, worldruntime.StaticActorCombatKindTrainingDummy)
	if !ok {
		t.Fatal("expected visible training-dummy registration to succeed")
	}
	flow, enterOut := enterGameWithLoginTicket(t, runtime.SessionFactory(), "killer", 0x11111111)
	defer closeSessionFlow(t, flow)
	if len(enterOut) != 8 {
		t.Fatalf("expected 8 bootstrap frames with visible training dummy, got %d", len(enterOut))
	}

	targetVID := uint32(actor.EntityID)
	selectOut, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected combat target error before snapshot death check: %v", err)
	}
	if len(selectOut) != 1 {
		t.Fatalf("expected 1 self-only target frame before snapshot death check, got %d", len(selectOut))
	}
	for attackIndex := 0; attackIndex < 10; attackIndex++ {
		if attackIndex > 0 {
			currentTime = currentTime.Add(bootstrapNormalAttackCadenceWindow)
		}
		attackOut, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{AttackType: combatproto.ClientAttackTypeNormal, TargetVID: targetVID})))
		if err != nil {
			t.Fatalf("unexpected combat attack error on snapshot death hit %d: %v", attackIndex+1, err)
		}
		wantFrames := 1
		if attackIndex == 9 {
			wantFrames = 2
		}
		if len(attackOut) != wantFrames {
			t.Fatalf("expected %d attack frames on snapshot death hit %d, got %d", wantFrames, attackIndex+1, len(attackOut))
		}
	}

	actors := runtime.StaticActors()
	if len(actors) != 1 || actors[0].EntityID != actor.EntityID || !actors[0].Dead {
		t.Fatalf("expected runtime static-actor snapshot to mark dead training dummy, got %+v", actors)
	}
	visibility := runtime.CharacterVisibility()
	if len(visibility) != 1 || len(visibility[0].VisibleStaticActors) != 1 || visibility[0].VisibleStaticActors[0].EntityID != actor.EntityID || !visibility[0].VisibleStaticActors[0].Dead {
		t.Fatalf("expected character visibility snapshot to mark dead training dummy, got %+v", visibility)
	}
	occupancy := runtime.MapOccupancy()
	if len(occupancy) != 1 || occupancy[0].MapIndex != bootstrapMapIndex || len(occupancy[0].StaticActors) != 1 || occupancy[0].StaticActors[0].EntityID != actor.EntityID || !occupancy[0].StaticActors[0].Dead {
		t.Fatalf("expected map occupancy snapshot to mark dead training dummy, got %+v", occupancy)
	}
}

func TestGameRuntimePlayerSnapshotsMarkDeadOwner(t *testing.T) {
	store := loginticket.NewFileStore(t.TempDir())
	owner := peerVisibilityCharacter("Owner", 0x01030101, 0x02040101, 1100, 2100, 0, 101, 201)
	owner.Points[bootstrapPlayerPointValueIndex] = 1
	watcher := peerVisibilityCharacter("Watcher", 0x01030102, 0x02040102, 1300, 2300, 2, 102, 202)
	issuePeerTicket(t, store, "owner", 0x11111111, owner)
	issuePeerTicket(t, store, "watcher", 0x22222222, watcher)

	staticActorStore := staticstore.NewFileStore(t.TempDir() + "/static-actors.json")
	interactionStore := interactionstore.NewFileStore(t.TempDir() + "/interaction-definitions.json")
	runtime, err := newGameRuntimeWithAccountStoreAndContentStores(config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"}, store, nil, staticActorStore, interactionStore)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	bundle := contentbundle.Bundle{SpawnGroups: []contentbundle.SpawnGroup{{
		Ref:           "practice.mob_alpha",
		Name:          "PracticeMobAlpha",
		MapIndex:      bootstrapMapIndex,
		X:             1200,
		Y:             2200,
		RaceNum:       101,
		CombatProfile: string(worldruntime.StaticActorCombatProfileTrainingDummy),
	}}}
	if _, err := runtime.ImportContentBundle(bundle); err != nil {
		t.Fatalf("import content spawn-group bundle: %v", err)
	}
	actors := runtime.StaticActors()
	if len(actors) != 1 {
		t.Fatalf("expected 1 runtime practice-mob actor after import, got %#v", actors)
	}
	targetVID := uint32(actors[0].EntityID)

	ownerFlow, ownerEnter := enterGameWithLoginTicket(t, runtime.SessionFactory(), "owner", 0x11111111)
	if len(ownerEnter) != 8 {
		t.Fatalf("expected 8 bootstrap frames for owner with visible content practice mob, got %d", len(ownerEnter))
	}
	defer closeSessionFlow(t, ownerFlow)
	watcherFlow, watcherEnter := enterGameWithLoginTicket(t, runtime.SessionFactory(), "watcher", 0x22222222)
	if len(watcherEnter) != 11 {
		t.Fatalf("expected 11 bootstrap frames for watcher with visible owner and content practice mob, got %d", len(watcherEnter))
	}
	defer closeSessionFlow(t, watcherFlow)
	if queued := flushServerFrames(t, ownerFlow); len(queued) != 3 {
		t.Fatalf("expected 3 queued peer-visibility frames for owner after watcher joins, got %d", len(queued))
	}

	selectOut, err := ownerFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected target-selection error before dead-owner player snapshot check: %v", err)
	}
	if len(selectOut) != 1 {
		t.Fatalf("expected 1 target-selection frame before dead-owner player snapshot check, got %d", len(selectOut))
	}
	attackOut, err := ownerFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{
		AttackType: combatproto.ClientAttackTypeNormal,
		TargetVID:  targetVID,
	})))
	if err != nil {
		t.Fatalf("unexpected attack error before dead-owner player snapshot check: %v", err)
	}
	if len(attackOut) == 0 {
		t.Fatal("expected accepted attack frames before dead-owner player snapshot check")
	}

	connected := runtime.ConnectedCharacters()
	if len(connected) != 2 {
		t.Fatalf("expected 2 connected character snapshots after owner reaches HP floor, got %+v", connected)
	}
	var connectedOwner, connectedWatcher *ConnectedCharacterSnapshot
	for i := range connected {
		switch connected[i].Name {
		case "Owner":
			connectedOwner = &connected[i]
		case "Watcher":
			connectedWatcher = &connected[i]
		}
	}
	if connectedOwner == nil || !connectedOwner.Dead {
		t.Fatalf("expected connected owner snapshot to be marked dead after retaliation HP floor, got %+v", connected)
	}
	if connectedWatcher == nil || connectedWatcher.Dead {
		t.Fatalf("expected watcher connected snapshot to remain live after owner retaliation HP floor, got %+v", connected)
	}

	visibility := runtime.CharacterVisibility()
	if len(visibility) != 2 {
		t.Fatalf("expected 2 character visibility snapshots after owner reaches HP floor, got %+v", visibility)
	}
	var ownerVisibility, watcherVisibility *CharacterVisibilitySnapshot
	for i := range visibility {
		switch visibility[i].Name {
		case "Owner":
			ownerVisibility = &visibility[i]
		case "Watcher":
			watcherVisibility = &visibility[i]
		}
	}
	if ownerVisibility == nil || !ownerVisibility.Dead {
		t.Fatalf("expected owner visibility snapshot to be marked dead after retaliation HP floor, got %+v", visibility)
	}
	if watcherVisibility == nil || watcherVisibility.Dead {
		t.Fatalf("expected watcher visibility snapshot to remain live after owner retaliation HP floor, got %+v", visibility)
	}
	if len(watcherVisibility.VisiblePeers) != 1 || watcherVisibility.VisiblePeers[0].Name != "Owner" || !watcherVisibility.VisiblePeers[0].Dead {
		t.Fatalf("expected watcher visible-peer snapshot to preserve dead owner state, got %+v", watcherVisibility.VisiblePeers)
	}

	interactionVisibility := runtime.InteractionVisibility()
	if len(interactionVisibility) != 2 {
		t.Fatalf("expected 2 interaction-visibility snapshots after owner reaches HP floor, got %+v", interactionVisibility)
	}
	var interactionOwner, interactionWatcher *CharacterInteractionVisibilitySnapshot
	for i := range interactionVisibility {
		switch interactionVisibility[i].Name {
		case "Owner":
			interactionOwner = &interactionVisibility[i]
		case "Watcher":
			interactionWatcher = &interactionVisibility[i]
		}
	}
	if interactionOwner == nil || !interactionOwner.Dead {
		t.Fatalf("expected interaction-visibility owner snapshot to be marked dead after retaliation HP floor, got %+v", interactionVisibility)
	}
	if interactionWatcher == nil || interactionWatcher.Dead {
		t.Fatalf("expected interaction-visibility watcher snapshot to remain live after owner retaliation HP floor, got %+v", interactionVisibility)
	}

	occupancy := runtime.MapOccupancy()
	if len(occupancy) != 1 || occupancy[0].MapIndex != bootstrapMapIndex || len(occupancy[0].Characters) != 2 {
		t.Fatalf("expected one map-occupancy snapshot with both characters after owner reaches HP floor, got %+v", occupancy)
	}
	var occupancyOwner, occupancyWatcher *ConnectedCharacterSnapshot
	for i := range occupancy[0].Characters {
		switch occupancy[0].Characters[i].Name {
		case "Owner":
			occupancyOwner = &occupancy[0].Characters[i]
		case "Watcher":
			occupancyWatcher = &occupancy[0].Characters[i]
		}
	}
	if occupancyOwner == nil || !occupancyOwner.Dead {
		t.Fatalf("expected map-occupancy owner snapshot to be marked dead after retaliation HP floor, got %+v", occupancy)
	}
	if occupancyWatcher == nil || occupancyWatcher.Dead {
		t.Fatalf("expected map-occupancy watcher snapshot to remain live after owner retaliation HP floor, got %+v", occupancy)
	}
}

func TestGameRuntimeTransferCharacterStructuredSnapshotsMarkDeadTrainingDummy(t *testing.T) {
	store := loginticket.NewFileStore(t.TempDir())
	killer := peerVisibilityCharacter("Killer", 0x01030101, 0x02040101, 1700, 2800, 0, 101, 201)
	killer.MapIndex = 42
	mover := peerVisibilityCharacter("Mover", 0x01030102, 0x02040102, 1300, 2300, 2, 102, 202)
	issuePeerTicket(t, store, "killer", 0x11111111, killer)
	issuePeerTicket(t, store, "mover", 0x22222222, mover)

	runtime, err := newGameRuntimeWithAccountStore(config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"}, store, nil)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	currentTime := time.Unix(1700000306, 0)
	runtime.now = func() time.Time { return currentTime }
	actor, ok := runtime.sharedWorld.RegisterStaticActorWithCombatKind(0, "TrainingDummy", 42, 1700, 2800, 20350, worldruntime.StaticActorCombatKindTrainingDummy)
	if !ok {
		t.Fatal("expected target-map training-dummy registration to succeed")
	}
	killerFlow, killerEnter := enterGameWithLoginTicket(t, runtime.SessionFactory(), "killer", 0x11111111)
	if len(killerEnter) != 8 {
		t.Fatalf("expected 8 bootstrap frames for killer on target map, got %d", len(killerEnter))
	}
	targetVID := uint32(actor.EntityID)
	selectOut, err := killerFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected combat target error before structured-result death check: %v", err)
	}
	if len(selectOut) != 1 {
		t.Fatalf("expected 1 self-only target frame before structured-result death check, got %d", len(selectOut))
	}
	for attackIndex := 0; attackIndex < 10; attackIndex++ {
		if attackIndex > 0 {
			currentTime = currentTime.Add(bootstrapNormalAttackCadenceWindow)
		}
		attackOut, err := killerFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{AttackType: combatproto.ClientAttackTypeNormal, TargetVID: targetVID})))
		if err != nil {
			t.Fatalf("unexpected combat attack error on structured-result death hit %d: %v", attackIndex+1, err)
		}
		wantFrames := 1
		if attackIndex == 9 {
			wantFrames = 2
		}
		if len(attackOut) != wantFrames {
			t.Fatalf("expected %d attack frames on structured-result death hit %d, got %d", wantFrames, attackIndex+1, len(attackOut))
		}
	}
	closeSessionFlow(t, killerFlow)

	moverFlow, moverEnter := enterGameWithLoginTicket(t, runtime.SessionFactory(), "mover", 0x22222222)
	defer closeSessionFlow(t, moverFlow)
	if len(moverEnter) != 5 {
		t.Fatalf("expected 5 source-map bootstrap frames for mover before transfer, got %d", len(moverEnter))
	}

	preview, ok := runtime.PreviewRelocation("Mover", 42, 1700, 2800)
	if !ok {
		t.Fatal("expected relocation preview into dead training-dummy visibility to succeed")
	}
	if len(preview.TargetVisibleStaticActors) != 1 || preview.TargetVisibleStaticActors[0].EntityID != actor.EntityID || !preview.TargetVisibleStaticActors[0].Dead {
		t.Fatalf("expected relocation preview target-visible static actor to stay dead, got %+v", preview.TargetVisibleStaticActors)
	}
	if len(preview.AddedVisibleStaticActors) != 1 || preview.AddedVisibleStaticActors[0].EntityID != actor.EntityID || !preview.AddedVisibleStaticActors[0].Dead {
		t.Fatalf("expected relocation preview added static actor to stay dead, got %+v", preview.AddedVisibleStaticActors)
	}
	previewTargetOccupancy := preview.AfterMapOccupancy[0]
	if previewTargetOccupancy.MapIndex != 42 || len(previewTargetOccupancy.StaticActors) != 1 || previewTargetOccupancy.StaticActors[0].EntityID != actor.EntityID || !previewTargetOccupancy.StaticActors[0].Dead {
		t.Fatalf("expected relocation preview after-map occupancy to keep dead training dummy state, got %+v", preview.AfterMapOccupancy)
	}

	result, ok := runtime.TransferCharacter("Mover", 42, 1700, 2800)
	if !ok {
		t.Fatal("expected transfer into dead training-dummy visibility to succeed")
	}
	if !result.Applied {
		t.Fatal("expected transfer result to be marked applied")
	}
	if len(result.TargetVisibleStaticActors) != 1 || result.TargetVisibleStaticActors[0].EntityID != actor.EntityID || !result.TargetVisibleStaticActors[0].Dead {
		t.Fatalf("expected transfer target-visible static actor to stay dead, got %+v", result.TargetVisibleStaticActors)
	}
	if len(result.AddedVisibleStaticActors) != 1 || result.AddedVisibleStaticActors[0].EntityID != actor.EntityID || !result.AddedVisibleStaticActors[0].Dead {
		t.Fatalf("expected transfer added static actor to stay dead, got %+v", result.AddedVisibleStaticActors)
	}
	resultTargetOccupancy := result.AfterMapOccupancy[0]
	if resultTargetOccupancy.MapIndex != 42 || len(resultTargetOccupancy.StaticActors) != 1 || resultTargetOccupancy.StaticActors[0].EntityID != actor.EntityID || !resultTargetOccupancy.StaticActors[0].Dead {
		t.Fatalf("expected transfer after-map occupancy to keep dead training dummy state, got %+v", result.AfterMapOccupancy)
	}
}

