func TestGameRuntimePracticeMobRespawnPreservesAuthoredSpawnRewardSnapshot(t *testing.T) {
	store := loginticket.NewFileStore(t.TempDir())
	nearPlayer := peerVisibilityCharacter("RewardRespawnNear", 0x01030111, 0x02040111, 1100, 2100, 0, 101, 201)
	issuePeerTicket(t, store, "reward-respawn-near", 0x11111111, nearPlayer)

	staticActorStore := staticstore.NewFileStore(t.TempDir() + "/static-actors.json")
	interactionStore := interactionstore.NewFileStore(t.TempDir() + "/interaction-definitions.json")
	runtime, err := newGameRuntimeWithStoresAndTransferTriggersAndItemStore(config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"}, store, nil, staticActorStore, interactionStore, itemcatalog.NewFileStore(t.TempDir()+"/item-templates.json"), nil)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	currentTime := time.Unix(1700000601, 0)
	runtime.now = func() time.Time { return currentTime }
	bundle := contentbundle.Bundle{
		SpawnGroups: []contentbundle.SpawnGroup{{
			Ref:              "practice.reward_respawn",
			Name:             "RewardRespawnMob",
			MapIndex:         bootstrapMapIndex,
			X:                1200,
			Y:                2200,
			RaceNum:          20350,
			CombatProfile:    string(worldruntime.StaticActorCombatProfileTrainingDummy),
			RewardExperience: 7,
			RewardGold:       13,
			RewardDropVnums:  []uint32{3001, 3002},
		}},
		ItemTemplates: rewardDropItemTemplates(3001, 3002),
	}
	if _, err := runtime.ImportContentBundle(bundle); err != nil {
		t.Fatalf("import reward respawn spawn-group bundle: %v", err)
	}
	actors := runtime.StaticActors()
	if len(actors) != 1 {
		t.Fatalf("expected 1 reward respawn actor after import, got %#v", actors)
	}
	actor := actors[0]
	if actor.RewardExperience != 7 || actor.RewardGold != 13 || !reflect.DeepEqual(actor.RewardDropVnums, []uint32{3001, 3002}) {
		t.Fatalf("unexpected imported reward respawn actor snapshot: %+v", actor)
	}

	flow, enterOut := enterGameWithLoginTicket(t, runtime.SessionFactory(), "reward-respawn-near", 0x11111111)
	defer closeSessionFlow(t, flow)
	if len(enterOut) != 8 {
		t.Fatalf("expected 8 bootstrap frames for nearby player with reward respawn actor, got %d", len(enterOut))
	}
	targetVID := uint32(actor.EntityID)
	selectOut, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected combat target error before reward respawn: %v", err)
	}
	if len(selectOut) != 1 {
		t.Fatalf("expected 1 target-selection frame before reward respawn, got %d", len(selectOut))
	}
	for attackIndex := 0; attackIndex < 10; attackIndex++ {
		if attackIndex > 0 {
			currentTime = currentTime.Add(bootstrapNormalAttackCadenceWindow)
		}
		attackOut, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{AttackType: combatproto.ClientAttackTypeNormal, TargetVID: targetVID})))
		if err != nil {
			t.Fatalf("unexpected combat attack error on reward respawn hit %d: %v", attackIndex+1, err)
		}
		if len(attackOut) == 0 {
			t.Fatalf("expected accepted attack frames on reward respawn hit %d", attackIndex+1)
		}
	}

	currentTime = currentTime.Add(worldruntime.TrainingDummyBootstrapRespawnDelay)
	respawnFrames := flushServerFrames(t, flow)
	if len(respawnFrames) != 4 {
		t.Fatalf("expected delete/add/info/update reward respawn rebuild, got %d frames", len(respawnFrames))
	}
	postRespawn := runtime.StaticActors()
	if len(postRespawn) != 1 {
		t.Fatalf("expected 1 reward respawn actor after respawn, got %#v", postRespawn)
	}
	if postRespawn[0].EntityID != actor.EntityID || postRespawn[0].SpawnGroupRef != "practice.reward_respawn" || postRespawn[0].RewardExperience != 7 || postRespawn[0].RewardGold != 13 || !reflect.DeepEqual(postRespawn[0].RewardDropVnums, []uint32{3001, 3002}) {
		t.Fatalf("expected respawn to preserve authored reward snapshot, got %+v", postRespawn[0])
	}
}

func TestGameRuntimeRegisteredProfileRespawnUsesRegisteredDelayAndFullHP(t *testing.T) {
	const profile = "practice_respawn_profile_wolf"
	if !worldruntime.RegisterStaticActorCombatProfile(profile, worldruntime.StaticActorCombatProfileDefaults{
		MaxHP:                 4,
		DamagePerNormalAttack: 2,
		RespawnDelay:          1500 * time.Millisecond,
	}) {
		t.Fatalf("expected %q profile registration with custom respawn defaults to succeed", profile)
	}
	t.Cleanup(func() { worldruntime.UnregisterStaticActorCombatProfileForTest(profile) })

	store := loginticket.NewFileStore(t.TempDir())
	nearPlayer := peerVisibilityCharacter("RegisteredRespawnNear", 0x01030121, 0x02040121, 1100, 2100, 0, 101, 201)
	issuePeerTicket(t, store, "registered-respawn-near", 0x11111121, nearPlayer)

	runtime, err := newGameRuntimeWithAccountStore(config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"}, store, nil)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	currentTime := time.Unix(1700000602, 0)
	runtime.now = func() time.Time { return currentTime }
	actor, ok := runtime.sharedWorld.registerStaticActor(0, "RegisteredRespawnMob", bootstrapMapIndex, 1200, 2200, 20350, "", "", profile, "practice.registered_respawn", worldruntime.StaticActorDeathReward{})
	if !ok {
		t.Fatal("expected spawn-backed registered-profile actor registration to succeed")
	}

	flow, enterOut := enterGameWithLoginTicket(t, runtime.SessionFactory(), "registered-respawn-near", 0x11111121)
	defer closeSessionFlow(t, flow)
	if len(enterOut) != 8 {
		t.Fatalf("expected 8 bootstrap frames for nearby player with registered-profile actor, got %d", len(enterOut))
	}
	targetVID := uint32(actor.EntityID)
	selectOut, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected registered-profile combat target error before respawn: %v", err)
	}
	if len(selectOut) != 1 {
		t.Fatalf("expected 1 target-selection frame before registered-profile respawn, got %d", len(selectOut))
	}

	firstHit, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{AttackType: combatproto.ClientAttackTypeNormal, TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected registered-profile first attack error: %v", err)
	}
	if len(firstHit) != 2 {
		t.Fatalf("expected first registered-profile hit to return HP refresh plus self-only retaliation point-loss, got %d frames", len(firstHit))
	}
	firstRefresh, err := combatproto.DecodeServerTarget(decodeSingleFrame(t, firstHit[0]))
	if err != nil {
		t.Fatalf("decode first registered-profile HP refresh: %v", err)
	}
	if firstRefresh.TargetVID != targetVID || firstRefresh.HPPercent != 50 {
		t.Fatalf("expected registered profile 4 HP / 2 damage hit to report 50%% HP, got %+v", firstRefresh)
	}
	firstRetaliation, err := worldproto.DecodePlayerPointChange(decodeSingleFrame(t, firstHit[1]))
	if err != nil {
		t.Fatalf("decode first registered-profile retaliation point-change: %v", err)
	}
	if firstRetaliation.VID != nearPlayer.VID || firstRetaliation.Type != bootstrapPlayerPointType || firstRetaliation.Amount != -1 || firstRetaliation.Value != nearPlayer.Points[bootstrapPlayerPointValueIndex]-1 {
		t.Fatalf("unexpected first registered-profile retaliation point-change: %+v", firstRetaliation)
	}

	currentTime = currentTime.Add(bootstrapNormalAttackCadenceWindow)
	killingHit, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{AttackType: combatproto.ClientAttackTypeNormal, TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected registered-profile killing attack error: %v", err)
	}
	if len(killingHit) != 2 {
		t.Fatalf("expected registered-profile killing hit to return death + clear, got %d frames", len(killingHit))
	}

	currentTime = currentTime.Add(1499 * time.Millisecond)
	if early := flushServerFrames(t, flow); len(early) != 0 {
		t.Fatalf("expected no registered-profile respawn frames before custom delay expires, got %d", len(early))
	}
	currentTime = currentTime.Add(time.Millisecond)
	respawnFrames := flushServerFrames(t, flow)
	if len(respawnFrames) != 4 {
		t.Fatalf("expected delete/add/info/update registered-profile respawn rebuild, got %d frames", len(respawnFrames))
	}

	postRespawnTargetOut, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected post-respawn registered-profile target error: %v", err)
	}
	if len(postRespawnTargetOut) != 1 {
		t.Fatalf("expected fresh registered-profile target acquisition after respawn, got %d self frames", len(postRespawnTargetOut))
	}
	postRespawnRefresh, err := combatproto.DecodeServerTarget(decodeSingleFrame(t, postRespawnTargetOut[0]))
	if err != nil {
		t.Fatalf("decode post-respawn registered-profile target refresh: %v", err)
	}
	if postRespawnRefresh.TargetVID != targetVID || postRespawnRefresh.HPPercent != 100 {
		t.Fatalf("expected registered-profile respawn to restore full HP, got %+v", postRespawnRefresh)
	}
}

