func TestGameSessionFlowPracticeMobDelayedServerOriginRetaliationStopsAfterMobDeathAndRespawn(t *testing.T) {
	store := loginticket.NewFileStore(t.TempDir())
	owner := peerVisibilityCharacter("PeerOne", 0x01030101, 0x02040101, 1100, 2100, 0, 101, 201)
	owner.Points[bootstrapPlayerPointValueIndex] = 50
	issuePeerTicket(t, store, "peer-one", 0x11111111, owner)

	staticActorStore := staticstore.NewFileStore(t.TempDir() + "/static-actors.json")
	interactionStore := interactionstore.NewFileStore(t.TempDir() + "/interaction-definitions.json")
	runtime, err := newGameRuntimeWithAccountStoreAndContentStores(config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"}, store, nil, staticActorStore, interactionStore)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	currentTime := time.Unix(1700000450, 0)
	runtime.now = func() time.Time { return currentTime }
	bundle := contentbundle.Bundle{SpawnGroups: []contentbundle.SpawnGroup{{
		Ref:           "practice.mob_retaliation_cleanup",
		Name:          "PracticeMobRetaliationCleanup",
		MapIndex:      bootstrapMapIndex,
		X:             1200,
		Y:             2200,
		RaceNum:       101,
		CombatProfile: string(worldruntime.StaticActorCombatProfileTrainingDummy),
	}}}
	if _, err := runtime.ImportContentBundle(bundle); err != nil {
		t.Fatalf("import content spawn-group bundle: %v", err)
	}
	actors := runtime.StaticActors()
	if len(actors) != 1 {
		t.Fatalf("expected 1 runtime practice-mob actor after import, got %#v", actors)
	}
	targetVID := uint32(actors[0].EntityID)

	flow, enterOut := enterGameWithLoginTicket(t, runtime.SessionFactory(), "peer-one", 0x11111111)
	if len(enterOut) != 8 {
		t.Fatalf("expected 8 bootstrap frames for owner with visible content practice mob, got %d", len(enterOut))
	}
	defer closeSessionFlow(t, flow)

	selectOut, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected target-selection error before mob-death retaliation cleanup test: %v", err)
	}
	if len(selectOut) != 1 {
		t.Fatalf("expected 1 self-only target frame before mob-death retaliation cleanup test, got %d", len(selectOut))
	}

	firstAttack, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{
		AttackType: combatproto.ClientAttackTypeNormal,
		TargetVID:  targetVID,
	})))
	if err != nil {
		t.Fatalf("unexpected first attack error before mob-death retaliation cleanup test: %v", err)
	}
	if len(firstAttack) != 2 {
		t.Fatalf("expected first hit to arm delayed retaliation and append immediate point-loss, got %d frames", len(firstAttack))
	}
	var killingAttack [][]byte
	for attackIndex := 1; attackIndex < int(worldruntime.TrainingDummyBootstrapMaxHP); attackIndex++ {
		currentTime = currentTime.Add(bootstrapNormalAttackCadenceWindow)
		attackOut, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{
			AttackType: combatproto.ClientAttackTypeNormal,
			TargetVID:  targetVID,
		})))
		if err != nil {
			t.Fatalf("unexpected attack %d before mob-death retaliation cleanup test: %v", attackIndex+1, err)
		}
		if attackIndex == int(worldruntime.TrainingDummyBootstrapMaxHP)-1 {
			killingAttack = attackOut
			break
		}
		if len(attackOut) != 2 {
			t.Fatalf("expected live hit %d to return target refresh plus immediate retaliation, got %d frames", attackIndex+1, len(attackOut))
		}
	}
	if len(killingAttack) != 2 {
		t.Fatalf("expected killing hit to emit mob DEAD plus target clear without extra retaliation, got %d frames", len(killingAttack))
	}
	dead, err := worldproto.DecodeDead(decodeSingleFrame(t, killingAttack[0]))
	if err != nil {
		t.Fatalf("decode mob-death frame before retaliation cleanup: %v", err)
	}
	if dead.VID != targetVID {
		t.Fatalf("expected killing hit to kill target vid %d, got %+v", targetVID, dead)
	}
	clearTarget, err := combatproto.DecodeServerTarget(decodeSingleFrame(t, killingAttack[1]))
	if err != nil {
		t.Fatalf("decode target-clear frame after mob death before retaliation cleanup: %v", err)
	}
	if clearTarget.TargetVID != 0 || clearTarget.HPPercent != 0 {
		t.Fatalf("expected mob-death hit to clear selected target before retaliation cleanup, got %+v", clearTarget)
	}

	if queued := flushServerFrames(t, flow); len(queued) != 0 {
		t.Fatalf("expected delayed retaliation cadence to stop after mob death, got %d queued frames", len(queued))
	}
	currentTime = currentTime.Add(worldruntime.TrainingDummyBootstrapRespawnDelay)
	respawnFrames := flushServerFrames(t, flow)
	if len(respawnFrames) != 4 {
		t.Fatalf("expected respawn rebuild only after mob-death cleanup, got %d frames", len(respawnFrames))
	}
	respawnDelete, err := worldproto.DecodeCharacterDeleteNotice(decodeSingleFrame(t, respawnFrames[0]))
	if err != nil {
		t.Fatalf("decode respawn delete after mob-death cleanup: %v", err)
	}
	if respawnDelete.VID != targetVID {
		t.Fatalf("expected respawn delete for target vid %d, got %+v", targetVID, respawnDelete)
	}
	respawnAdd, err := worldproto.DecodeCharacterAdd(decodeSingleFrame(t, respawnFrames[1]))
	if err != nil {
		t.Fatalf("decode respawn add after mob-death cleanup: %v", err)
	}
	if respawnAdd.VID != targetVID || respawnAdd.X != 1200 || respawnAdd.Y != 2200 || respawnAdd.RaceNum != 101 {
		t.Fatalf("expected respawn add to rebuild target vid %d at original spawn, got %+v", targetVID, respawnAdd)
	}
	respawnInfo, err := worldproto.DecodeCharacterAdditionalInfo(decodeSingleFrame(t, respawnFrames[2]))
	if err != nil {
		t.Fatalf("decode respawn additional info after mob-death cleanup: %v", err)
	}
	if respawnInfo.VID != targetVID || respawnInfo.Name != "PracticeMobRetaliationCleanup" {
		t.Fatalf("expected respawn additional info to rebuild named target vid %d, got %+v", targetVID, respawnInfo)
	}
	respawnUpdate, err := worldproto.DecodeCharacterUpdate(decodeSingleFrame(t, respawnFrames[3]))
	if err != nil {
		t.Fatalf("decode respawn update after mob-death cleanup: %v", err)
	}
	if respawnUpdate.VID != targetVID {
		t.Fatalf("expected respawn update for target vid %d, got %+v", targetVID, respawnUpdate)
	}
	if queued := flushServerFrames(t, flow); len(queued) != 0 {
		t.Fatalf("expected no stale retaliation beat after respawn rebuild, got %d queued frames", len(queued))
	}
	postRespawnAttackOut, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{
		AttackType: combatproto.ClientAttackTypeNormal,
		TargetVID:  targetVID,
	})))
	if err != nil {
		t.Fatalf("unexpected post-respawn attack-without-reselect error after retaliation cleanup: %v", err)
	}
	if len(postRespawnAttackOut) != 0 {
		t.Fatalf("expected post-respawn attack without fresh target selection after retaliation cleanup to fail closed, got %d frames", len(postRespawnAttackOut))
	}
	postRespawnSelectOut, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected post-respawn reselect error after retaliation cleanup: %v", err)
	}
	if len(postRespawnSelectOut) != 1 {
		t.Fatalf("expected post-respawn reselect after retaliation cleanup to return 1 target frame, got %d", len(postRespawnSelectOut))
	}
	postRespawnSelected, err := combatproto.DecodeServerTarget(decodeSingleFrame(t, postRespawnSelectOut[0]))
	if err != nil {
		t.Fatalf("decode post-respawn reselect target after retaliation cleanup: %v", err)
	}
	if postRespawnSelected.TargetVID != targetVID || postRespawnSelected.HPPercent != 100 {
		t.Fatalf("expected post-respawn reselect to reacquire full-HP target vid %d, got %+v", targetVID, postRespawnSelected)
	}
	postRespawnAcceptedAttack, err := flow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{
		AttackType: combatproto.ClientAttackTypeNormal,
		TargetVID:  targetVID,
	})))
	if err != nil {
		t.Fatalf("unexpected post-respawn accepted attack error after retaliation cleanup: %v", err)
	}
	if len(postRespawnAcceptedAttack) != 2 {
		t.Fatalf("expected post-respawn accepted attack to restart target-refresh plus retaliation loop, got %d frames", len(postRespawnAcceptedAttack))
	}
	postRespawnRefresh, err := combatproto.DecodeServerTarget(decodeSingleFrame(t, postRespawnAcceptedAttack[0]))
	if err != nil {
		t.Fatalf("decode post-respawn accepted attack refresh after retaliation cleanup: %v", err)
	}
	if postRespawnRefresh.TargetVID != targetVID || postRespawnRefresh.HPPercent != 90 {
		t.Fatalf("expected post-respawn accepted attack to damage target to 90%% HP, got %+v", postRespawnRefresh)
	}
}

type tcpStartedSessionFlow struct {
	inner service.SessionFlow
}

func (f tcpStartedSessionFlow) Start() ([][]byte, error) {
	return nil, nil
}

func (f tcpStartedSessionFlow) HandleClientFrame(in frame.Frame) ([][]byte, error) {
	return f.inner.HandleClientFrame(in)
}

func (f tcpStartedSessionFlow) FlushServerFrames() ([][]byte, error) {
	if source, ok := f.inner.(service.ServerFrameSource); ok {
		return source.FlushServerFrames()
	}
	return nil, nil
}

func (f tcpStartedSessionFlow) Close() error {
	if closer, ok := f.inner.(io.Closer); ok {
		return closer.Close()
	}
	return nil
}

func writePlainTCPFrame(t *testing.T, conn net.Conn, raw []byte) {
	t.Helper()

	if err := conn.SetWriteDeadline(time.Now().Add(2 * time.Second)); err != nil {
		t.Fatalf("set tcp write deadline: %v", err)
	}
	for len(raw) > 0 {
		n, err := conn.Write(raw)
		if err != nil {
			t.Fatalf("write tcp frame: %v", err)
		}
		raw = raw[n:]
	}
}

func serveStartedFlowOverPlainTCP(t *testing.T, flow service.SessionFlow) (net.Conn, context.CancelFunc, <-chan error) {
	t.Helper()

	listener, err := net.Listen("tcp", "127.0.0.1:0")
	if err != nil {
		t.Fatalf("listen tcp: %v", err)
	}
	ctx, cancel := context.WithCancel(context.Background())
	errCh := make(chan error, 1)
	go func() {
		errCh <- service.ServeLegacy(ctx, listener, slog.New(slog.NewTextHandler(io.Discard, nil)), func() service.SessionFlow {
			return tcpStartedSessionFlow{inner: flow}
		})
	}()

	conn, err := net.Dial("tcp", listener.Addr().String())
	if err != nil {
		cancel()
		t.Fatalf("dial tcp: %v", err)
	}
	return conn, cancel, errCh
}

func stopPlainTCPServer(t *testing.T, conn net.Conn, cancel context.CancelFunc, errCh <-chan error) {
	t.Helper()

	_ = conn.Close()
	cancel()
	select {
	case err := <-errCh:
		if err != nil {
			t.Fatalf("ServeLegacy returned error: %v", err)
		}
	case <-time.After(2 * time.Second):
		t.Fatal("timeout waiting for ServeLegacy to stop")
	}
}

type plainTCPTestClient struct {
	conn    net.Conn
	decoder *frame.Decoder
	queued  []frame.Frame
}

func newPlainTCPTestClient(conn net.Conn) *plainTCPTestClient {
	return &plainTCPTestClient{conn: conn, decoder: frame.NewDecoder(8192)}
}

func (c *plainTCPTestClient) readFrame(t *testing.T) frame.Frame {
	t.Helper()
	if len(c.queued) > 0 {
		frame := c.queued[0]
		c.queued = c.queued[1:]
		return frame
	}
	buffer := make([]byte, 8192)
	for {
		if err := c.conn.SetReadDeadline(time.Now().Add(2 * time.Second)); err != nil {
			t.Fatalf("set tcp read deadline: %v", err)
		}
		n, err := c.conn.Read(buffer)
		if err != nil {
			t.Fatalf("read tcp frame: %v", err)
		}
		frames, err := c.decoder.Feed(buffer[:n])
		if err != nil {
			t.Fatalf("decode tcp frame: %v", err)
		}
		if len(frames) == 0 {
			continue
		}
		if len(frames) > 1 {
			c.queued = append(c.queued, frames[1:]...)
		}
		return frames[0]
	}
}

func (c *plainTCPTestClient) writeFrame(t *testing.T, raw []byte) {
	t.Helper()
	writePlainTCPFrame(t, c.conn, raw)
}

func (c *plainTCPTestClient) expectNoFrame(t *testing.T, context string) {
	t.Helper()
	if len(c.queued) != 0 {
		t.Fatalf("expected no queued tcp frame for %s, got %d", context, len(c.queued))
	}
	buffer := make([]byte, 8192)
	if err := c.conn.SetReadDeadline(time.Now().Add(100 * time.Millisecond)); err != nil {
		t.Fatalf("set tcp idle read deadline for %s: %v", context, err)
	}
	n, err := c.conn.Read(buffer)
	if err == nil {
		frames, decodeErr := c.decoder.Feed(buffer[:n])
		if decodeErr != nil {
			t.Fatalf("decode unexpected tcp idle bytes for %s: %v", context, decodeErr)
		}
		t.Fatalf("expected no tcp frame for %s, got %d decoded frames from %d bytes", context, len(frames), n)
	}
	if netErr, ok := err.(net.Error); ok && netErr.Timeout() {
		return
	}
	if errors.Is(err, os.ErrDeadlineExceeded) {
		return
	}
	t.Fatalf("expected tcp idle timeout for %s, got %v", context, err)
}

