func drivePracticeMobOwnerKill(t *testing.T, ownerFlow service.SessionFlow, targetVID uint32, context string, advance func(time.Duration)) [][]byte {
	t.Helper()

	selectOut, err := ownerFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected owner target-selection error before %s: %v", context, err)
	}
	if len(selectOut) != 1 {
		t.Fatalf("expected 1 owner target-selection frame before %s, got %d", context, len(selectOut))
	}

	var killingAttack [][]byte
	for attackIndex := 0; attackIndex < int(worldruntime.TrainingDummyBootstrapMaxHP); attackIndex++ {
		if attackIndex > 0 {
			advance(bootstrapNormalAttackCadenceWindow)
		}
		attackOut, err := ownerFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{
			AttackType: combatproto.ClientAttackTypeNormal,
			TargetVID:  targetVID,
		})))
		if err != nil {
			t.Fatalf("unexpected owner attack %d before %s: %v", attackIndex+1, context, err)
		}
		if attackIndex == int(worldruntime.TrainingDummyBootstrapMaxHP)-1 {
			killingAttack = attackOut
			break
		}
		if len(attackOut) != 2 {
			t.Fatalf("expected live owner hit %d before %s to return target refresh plus immediate retaliation, got %d frames", attackIndex+1, context, len(attackOut))
		}
	}
	if len(killingAttack) != 2 {
		t.Fatalf("expected killing owner hit before %s to emit mob dead plus target clear, got %d frames", context, len(killingAttack))
	}
	return killingAttack
}

func TestGameSessionFlowPracticeMobRespawnReleasesAggroForWatcherReselect(t *testing.T) {
	store := loginticket.NewFileStore(t.TempDir())
	owner := peerVisibilityCharacter("PeerOne", 0x01030101, 0x02040101, 1100, 2100, 0, 101, 201)
	owner.Points[bootstrapPlayerPointValueIndex] = 50
	watcher := peerVisibilityCharacter("PeerTwo", 0x01030102, 0x02040102, 1300, 2300, 0, 102, 202)
	issuePeerTicket(t, store, "peer-one", 0x11111111, owner)
	issuePeerTicket(t, store, "peer-two", 0x22222222, watcher)

	staticActorStore := staticstore.NewFileStore(t.TempDir() + "/static-actors.json")
	interactionStore := interactionstore.NewFileStore(t.TempDir() + "/interaction-definitions.json")
	runtime, err := newGameRuntimeWithAccountStoreAndContentStores(config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"}, store, nil, staticActorStore, interactionStore)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	currentTime := time.Unix(1700000450, 0)
	runtime.now = func() time.Time { return currentTime }
	bundle := contentbundle.Bundle{SpawnGroups: []contentbundle.SpawnGroup{{
		Ref:           "practice.mob_respawn_reselect",
		Name:          "PracticeMobRespawnReselect",
		MapIndex:      bootstrapMapIndex,
		X:             1200,
		Y:             2200,
		RaceNum:       101,
		CombatProfile: string(worldruntime.StaticActorCombatProfileTrainingDummy),
	}}}
	if _, err := runtime.ImportContentBundle(bundle); err != nil {
		t.Fatalf("import content spawn-group bundle: %v", err)
	}
	actors := runtime.StaticActors()
	if len(actors) != 1 {
		t.Fatalf("expected 1 runtime practice-mob actor after import, got %#v", actors)
	}
	targetVID := uint32(actors[0].EntityID)

	ownerFlow, ownerEnter := enterGameWithLoginTicket(t, runtime.SessionFactory(), "peer-one", 0x11111111)
	if len(ownerEnter) != 8 {
		t.Fatalf("expected 8 bootstrap frames for owner with visible content practice mob, got %d", len(ownerEnter))
	}
	defer closeSessionFlow(t, ownerFlow)
	watcherFlow, watcherEnter := enterGameWithLoginTicket(t, runtime.SessionFactory(), "peer-two", 0x22222222)
	if len(watcherEnter) != 11 {
		t.Fatalf("expected 11 bootstrap frames for watcher with visible owner and content practice mob, got %d", len(watcherEnter))
	}
	defer closeSessionFlow(t, watcherFlow)
	if queued := flushServerFrames(t, ownerFlow); len(queued) != 3 {
		t.Fatalf("expected 3 queued peer-visibility frames for owner after watcher joins, got %d", len(queued))
	}

	killingAttack := drivePracticeMobOwnerKill(t, ownerFlow, targetVID, "respawn reselect test", func(duration time.Duration) {
		currentTime = currentTime.Add(duration)
	})
	dead, err := worldproto.DecodeDead(decodeSingleFrame(t, killingAttack[0]))
	if err != nil {
		t.Fatalf("decode mob-death frame before respawn reselect test: %v", err)
	}
	if dead.VID != targetVID {
		t.Fatalf("expected owner killing hit to kill target vid %d, got %+v", targetVID, dead)
	}
	if queued := flushServerFrames(t, ownerFlow); len(queued) != 0 {
		t.Fatalf("expected no owner stale retaliation frames before respawn reselect test, got %d", len(queued))
	}
	if queued := flushServerFrames(t, watcherFlow); len(queued) != 1 {
		t.Fatalf("expected watcher to see exactly 1 mob-death frame before respawn reselect, got %d", len(queued))
	}
	preRespawnSelectOut, err := watcherFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected watcher target-selection error while mob is dead before respawn: %v", err)
	}
	if len(preRespawnSelectOut) != 0 {
		t.Fatalf("expected watcher target-selection while mob is dead before respawn to fail closed, got %d frames", len(preRespawnSelectOut))
	}

	currentTime = currentTime.Add(worldruntime.TrainingDummyBootstrapRespawnDelay)
	ownerRespawn := flushServerFrames(t, ownerFlow)
	if len(ownerRespawn) != 4 {
		t.Fatalf("expected owner to receive 4 respawn rebuild frames, got %d", len(ownerRespawn))
	}
	watcherRespawn := flushServerFrames(t, watcherFlow)
	if len(watcherRespawn) != 4 {
		t.Fatalf("expected watcher to receive 4 respawn rebuild frames, got %d", len(watcherRespawn))
	}
	watcherRespawnAdd, err := worldproto.DecodeCharacterAdd(decodeSingleFrame(t, watcherRespawn[1]))
	if err != nil {
		t.Fatalf("decode watcher respawn add before reselect: %v", err)
	}
	if watcherRespawnAdd.VID != targetVID || watcherRespawnAdd.X != 1200 || watcherRespawnAdd.Y != 2200 {
		t.Fatalf("expected watcher respawn add to make target visible again, got %+v", watcherRespawnAdd)
	}
	postRespawnStaleAttackOut, err := watcherFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{
		AttackType: combatproto.ClientAttackTypeNormal,
		TargetVID:  targetVID,
	})))
	if err != nil {
		t.Fatalf("unexpected watcher stale attack error after respawn before reselect: %v", err)
	}
	if len(postRespawnStaleAttackOut) != 0 {
		t.Fatalf("expected watcher stale attack after respawn before reselect to fail closed, got %d frames", len(postRespawnStaleAttackOut))
	}
	watcherReselectOut, err := watcherFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected watcher reselect error after respawn rebuild: %v", err)
	}
	if len(watcherReselectOut) != 1 {
		t.Fatalf("expected watcher reselect after respawn rebuild to return 1 target frame, got %d", len(watcherReselectOut))
	}
	watcherReselect, err := combatproto.DecodeServerTarget(decodeSingleFrame(t, watcherReselectOut[0]))
	if err != nil {
		t.Fatalf("decode watcher target frame after respawn rebuild: %v", err)
	}
	if watcherReselect.TargetVID != targetVID || watcherReselect.HPPercent != 100 {
		t.Fatalf("expected watcher to reselect respawned full-HP practice mob, got %+v", watcherReselect)
	}
	watcherAttackOut, err := watcherFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{
		AttackType: combatproto.ClientAttackTypeNormal,
		TargetVID:  targetVID,
	})))
	if err != nil {
		t.Fatalf("unexpected watcher attack after respawn reselect: %v", err)
	}
	if len(watcherAttackOut) != 2 {
		t.Fatalf("expected watcher attack after respawn reselect to restart target-refresh plus retaliation loop, got %d frames", len(watcherAttackOut))
	}
	watcherRefresh, err := combatproto.DecodeServerTarget(decodeSingleFrame(t, watcherAttackOut[0]))
	if err != nil {
		t.Fatalf("decode watcher attack refresh after respawn reselect: %v", err)
	}
	if watcherRefresh.TargetVID != targetVID || watcherRefresh.HPPercent != 90 {
		t.Fatalf("expected watcher attack after respawn reselect to damage target to 90%% HP, got %+v", watcherRefresh)
	}
	if queued := flushServerFrames(t, ownerFlow); len(queued) != 0 {
		t.Fatalf("expected owner to receive no stale frames after watcher restarts combat post-respawn, got %d", len(queued))
	}
}

func TestGameSessionFlowPracticeMobRespawnWatcherCombatBlocksSecondWatcher(t *testing.T) {
	store := loginticket.NewFileStore(t.TempDir())
	owner := peerVisibilityCharacter("PeerOne", 0x01030101, 0x02040101, 1100, 2100, 0, 101, 201)
	owner.Points[bootstrapPlayerPointValueIndex] = 50
	watcher := peerVisibilityCharacter("PeerTwo", 0x01030102, 0x02040102, 1300, 2300, 0, 102, 202)
	blocker := peerVisibilityCharacter("PeerThree", 0x01030103, 0x02040103, 1350, 2350, 0, 103, 203)
	issuePeerTicket(t, store, "peer-one", 0x11111111, owner)
	issuePeerTicket(t, store, "peer-two", 0x22222222, watcher)
	issuePeerTicket(t, store, "peer-three", 0x33333333, blocker)

	staticActorStore := staticstore.NewFileStore(t.TempDir() + "/static-actors.json")
	interactionStore := interactionstore.NewFileStore(t.TempDir() + "/interaction-definitions.json")
	runtime, err := newGameRuntimeWithAccountStoreAndContentStores(config.Service{LegacyAddr: ":13000", PublicAddr: "127.0.0.1"}, store, nil, staticActorStore, interactionStore)
	if err != nil {
		t.Fatalf("unexpected game runtime error: %v", err)
	}
	currentTime := time.Unix(1700000450, 0)
	runtime.now = func() time.Time { return currentTime }
	bundle := contentbundle.Bundle{SpawnGroups: []contentbundle.SpawnGroup{{
		Ref:           "practice.mob_respawn_second_block",
		Name:          "PracticeMobRespawnSecondBlock",
		MapIndex:      bootstrapMapIndex,
		X:             1200,
		Y:             2200,
		RaceNum:       101,
		CombatProfile: string(worldruntime.StaticActorCombatProfileTrainingDummy),
	}, {
		Ref:           "practice.mob_respawn_release_target",
		Name:          "PracticeMobRespawnReleaseTarget",
		MapIndex:      bootstrapMapIndex,
		X:             1250,
		Y:             2250,
		RaceNum:       101,
		CombatProfile: string(worldruntime.StaticActorCombatProfileTrainingDummy),
	}}}
	if _, err := runtime.ImportContentBundle(bundle); err != nil {
		t.Fatalf("import content spawn-group bundle: %v", err)
	}
	actors := runtime.StaticActors()
	if len(actors) != 2 {
		t.Fatalf("expected 2 runtime practice-mob actors after import, got %#v", actors)
	}
	targetVID := uint32(actors[0].EntityID)
	releaseTargetVID := uint32(actors[1].EntityID)

	ownerFlow, ownerEnter := enterGameWithLoginTicket(t, runtime.SessionFactory(), "peer-one", 0x11111111)
	if len(ownerEnter) != 11 {
		t.Fatalf("expected 11 bootstrap frames for owner with two visible content practice mobs, got %d", len(ownerEnter))
	}
	defer closeSessionFlow(t, ownerFlow)
	watcherFlow, watcherEnter := enterGameWithLoginTicket(t, runtime.SessionFactory(), "peer-two", 0x22222222)
	if len(watcherEnter) != 14 {
		t.Fatalf("expected 14 bootstrap frames for watcher with visible owner and two content practice mobs, got %d", len(watcherEnter))
	}
	defer closeSessionFlow(t, watcherFlow)
	if queued := flushServerFrames(t, ownerFlow); len(queued) != 3 {
		t.Fatalf("expected 3 queued peer-visibility frames for owner after watcher joins, got %d", len(queued))
	}
	blockerFlow, blockerEnter := enterGameWithLoginTicket(t, runtime.SessionFactory(), "peer-three", 0x33333333)
	if len(blockerEnter) != 17 {
		t.Fatalf("expected 17 bootstrap frames for blocker with two peers and two content practice mobs, got %d", len(blockerEnter))
	}
	defer closeSessionFlow(t, blockerFlow)
	if queued := flushServerFrames(t, ownerFlow); len(queued) != 3 {
		t.Fatalf("expected 3 queued blocker-visibility frames for owner, got %d", len(queued))
	}
	if queued := flushServerFrames(t, watcherFlow); len(queued) != 3 {
		t.Fatalf("expected 3 queued blocker-visibility frames for watcher, got %d", len(queued))
	}

	drivePracticeMobOwnerKill(t, ownerFlow, targetVID, "respawn second-watcher block test", func(duration time.Duration) {
		currentTime = currentTime.Add(duration)
	})
	if queued := flushServerFrames(t, ownerFlow); len(queued) != 0 {
		t.Fatalf("expected no owner stale retaliation frames before respawn second-watcher block test, got %d", len(queued))
	}
	if queued := flushServerFrames(t, watcherFlow); len(queued) != 1 {
		t.Fatalf("expected watcher to see exactly 1 mob-death frame before respawn second-watcher block test, got %d", len(queued))
	}
	if queued := flushServerFrames(t, blockerFlow); len(queued) != 1 {
		t.Fatalf("expected blocker to see exactly 1 mob-death frame before respawn second-watcher block test, got %d", len(queued))
	}

	currentTime = currentTime.Add(worldruntime.TrainingDummyBootstrapRespawnDelay)
	if ownerRespawn := flushServerFrames(t, ownerFlow); len(ownerRespawn) != 4 {
		t.Fatalf("expected owner to receive 4 respawn rebuild frames, got %d", len(ownerRespawn))
	}
	if watcherRespawn := flushServerFrames(t, watcherFlow); len(watcherRespawn) != 4 {
		t.Fatalf("expected watcher to receive 4 respawn rebuild frames, got %d", len(watcherRespawn))
	}
	if blockerRespawn := flushServerFrames(t, blockerFlow); len(blockerRespawn) != 4 {
		t.Fatalf("expected blocker to receive 4 respawn rebuild frames, got %d", len(blockerRespawn))
	}
	watcherReselectOut, err := watcherFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected watcher reselect error after respawn rebuild: %v", err)
	}
	if len(watcherReselectOut) != 1 {
		t.Fatalf("expected watcher reselect after respawn rebuild to return 1 target frame, got %d", len(watcherReselectOut))
	}
	watcherAttackOut, err := watcherFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientAttack(combatproto.ClientAttackPacket{AttackType: combatproto.ClientAttackTypeNormal, TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected watcher attack after respawn reselect: %v", err)
	}
	if len(watcherAttackOut) != 2 {
		t.Fatalf("expected watcher attack after respawn reselect to restart target-refresh plus retaliation loop, got %d frames", len(watcherAttackOut))
	}
	blockedTargetOut, err := blockerFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected blocker target-selection error while watcher holds post-respawn aggro-lite gate: %v", err)
	}
	if len(blockedTargetOut) != 0 {
		t.Fatalf("expected blocker target-selection to fail closed while watcher holds post-respawn aggro-lite gate, got %d frames", len(blockedTargetOut))
	}
	watcherRetargetOut, err := watcherFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: releaseTargetVID})))
	if err != nil {
		t.Fatalf("unexpected watcher retarget after post-respawn combat: %v", err)
	}
	if len(watcherRetargetOut) != 1 {
		t.Fatalf("expected watcher retarget to second mob after post-respawn combat to return 1 target frame, got %d", len(watcherRetargetOut))
	}
	releasedTargetOut, err := blockerFlow.HandleClientFrame(decodeSingleFrame(t, combatproto.EncodeClientTarget(combatproto.ClientTargetPacket{TargetVID: targetVID})))
	if err != nil {
		t.Fatalf("unexpected blocker target-selection after watcher post-respawn retarget released first mob: %v", err)
	}
	if len(releasedTargetOut) != 1 {
		t.Fatalf("expected blocker target-selection to succeed after watcher post-respawn retarget released first mob, got %d frames", len(releasedTargetOut))
	}
	releasedTarget, err := combatproto.DecodeServerTarget(decodeSingleFrame(t, releasedTargetOut[0]))
	if err != nil {
		t.Fatalf("decode blocker released-target frame after watcher post-respawn retarget: %v", err)
	}
	if releasedTarget.TargetVID != targetVID || releasedTarget.HPPercent != 90 {
		t.Fatalf("expected blocker to reacquire first post-respawn mob at current HP after watcher retarget release, got %+v", releasedTarget)
	}
}

